def agora_brasilia():
    """Retorna a data/hora atual no horário oficial de Brasília, UTC-03:00."""
    return datetime.now(timezone.utc).astimezone(FUSO_HORARIO_BRASILIA)


def agora_iso():
    """Retorna data/hora atual de Brasília em ISO-8601 com deslocamento -03:00."""
    return agora_brasilia().replace(microsecond=0).isoformat()


def agora_texto_brasilia():
    """Retorna data/hora atual de Brasília para exibição."""
    return agora_brasilia().strftime("%d/%m/%Y %H:%M")


def hoje_ddmmaaaa():
    """Retorna a data atual de Brasília no formato dd/mm/aaaa."""
    return agora_brasilia().strftime("%d/%m/%Y")


def parse_data(valor):
    if valor is None or valor == "":
        return None

    if isinstance(valor, datetime):
        return valor.date()

    if isinstance(valor, date):
        return valor

    texto = str(valor).strip()

    for fmt in ("%d/%m/%Y", "%Y-%m-%d", "%d-%m-%Y", "%d/%m/%y"):
        try:
            return datetime.strptime(texto, fmt).date()
        except Exception:
            pass

    try:
        return pd.to_datetime(texto, dayfirst=True, errors="coerce").date()
    except Exception:
        return None


def data_para_exibir(valor):
    d = parse_data(valor)
    if d:
        return d.strftime("%d/%m/%Y")
    return ""


def formatar_data_hora_brasilia(valor):
    if valor is None or valor == "":
        return ""

    texto = str(valor).strip().replace("\n", "").replace("\r", "")
    if not texto:
        return ""

    if re.match(r"^\d{2}/\d{2}/\d{4} \d{2}:\d{2}$", texto):
        return texto

    try:
        if texto.endswith("Z"):
            texto = texto[:-1] + "+00:00"

        if " " in texto and "T" not in texto:
            texto = texto.replace(" ", "T")

        dt = datetime.fromisoformat(texto)

        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)

        return dt.astimezone(FUSO_HORARIO_BRASILIA).strftime("%d/%m/%Y %H:%M")
    except Exception:
        return texto


def iso_para_exibir(valor):
    return formatar_data_hora_brasilia(valor)





def normalizar_complexidade(valor):
    texto = str(valor or "").strip()
    for item in COMPLEXIDADES_ATENDIMENTO:
        if texto.casefold() == item.casefold():
            return item
    return "Não informada"


def perfil_normalizado(valor):
    texto = str(valor or "").strip()
    if texto in PERFIS_USUARIO:
        return texto
    if texto == "Administrador":
        return "Administrador geral"
    if texto == "Usuário":
        return "Operador SEPRO"
    return "Operador SEPRO"


def usuario_pode_ver_secao(secao):
    usuario = usuario_logado()
    if not usuario:
        return False

    perfil = perfil_normalizado(usuario.get("perfil"))
    secao_usuario = normalizar_secao(usuario.get("secao_operador") or usuario.get("secao") or "SEPRO")
    secao = normalizar_secao(secao)

    if perfil in ("Administrador geral", "Administrador", "Consulta"):
        return True

    # Perfis no formato "Chefia SEOCE", "Operador SEPRO" etc.
    for prefixo in ("Chefia ", "Operador "):
        if perfil.startswith(prefixo):
            secao_perfil = normalizar_secao(perfil.replace(prefixo, "", 1))
            return secao_perfil == secao

    return secao_usuario == secao


def filtrar_lista_por_perfil(lista):
    usuario = usuario_logado()
    if not usuario:
        return []
    if eh_admin():
        return lista
    perfil = perfil_normalizado(usuario.get("perfil"))
    if perfil == "Consulta":
        return lista
    return [a for a in lista if usuario_pode_ver_secao(a.get("secao"))]


def parse_data_opcional(valor):
    if valor in (None, "", "Não informado"):
        return None
    return parse_data(valor)



def normalizar_secao(valor):
    """
    Normalização rápida de seção.

    Importante: esta função é chamada centenas/milhares de vezes ao montar o
    painel. Por isso, ela não consulta o Supabase. Usa apenas o mapa de siglas
    legadas e a lista local/cacheada.
    """
    texto = str(valor or "").strip().upper()
    texto = SECOES_LEGADAS.get(texto, texto)

    secoes_validas = st.session_state.get("_secoes_atendimento_cache") or list(SECOES_ATENDIMENTO)

    if texto in secoes_validas:
        return texto

    return secoes_validas[0] if secoes_validas else "SEPRO"


def secoes_atendimento(forcar_atualizacao=False):
    """
    Retorna as seções ativas da Corregedoria.

    Mantém o painel completo e evita lentidão: antes do login usa fallback local;
    depois do login consulta a tabela public.secoes no máximo uma vez por sessão,
    salvo atualização manual.
    """
    fallback = list(SECOES_ATENDIMENTO)

    try:
        if not st.session_state.get("usuario"):
            return fallback

        if not forcar_atualizacao:
            cached = st.session_state.get("_secoes_atendimento_cache")
            if cached:
                return cached

        rows = supabase_get_silencioso(
            "secoes",
            {"select": "sigla,ativo,ordem", "ativo": "eq.true", "order": "ordem.asc,sigla.asc"}
        )

        siglas = []
        for row in rows or []:
            sigla = str(row.get("sigla") or "").strip().upper()
            sigla = SECOES_LEGADAS.get(sigla, sigla)
            if sigla and sigla not in siglas:
                siglas.append(sigla)

        if siglas:
            st.session_state["_secoes_atendimento_cache"] = siglas
            return siglas

    except Exception:
        pass

    return fallback

def senha_hash(senha):
    return hashlib.sha256(str(senha).encode("utf-8")).hexdigest()


def carregar_json(caminho, padrao):
    if not caminho.exists():
        return padrao
    try:
        return json.loads(caminho.read_text(encoding="utf-8"))
    except Exception:
        return padrao


def salvar_json(caminho, dados):
    caminho.write_text(json.dumps(dados, ensure_ascii=False, indent=2), encoding="utf-8")


def supabase_config():
    """Lê e normaliza as configurações do Supabase nos Secrets."""
    url = str(st.secrets.get("SUPABASE_URL", "")).strip().strip('"').strip("'").rstrip("/")
    key = str(st.secrets.get("SUPABASE_KEY", "")).strip().strip('"').strip("'")
    return url, key


def supabase_headers():
    _, key = supabase_config()
    return {
        "apikey": key,
        "Authorization": f"Bearer {key}",
        "Content-Type": "application/json",
        "Prefer": "return=representation",
    }


def supabase_rest_url(tabela):
    url, key = supabase_config()

    if not url or not key:
        st.error(
            "Supabase não configurado. Configure SUPABASE_URL e SUPABASE_KEY "
            "em Gerenciar aplicativo > Settings > Secrets."
        )
        st.stop()

    if not url.startswith("https://") or not url.endswith(".supabase.co"):
        st.error("SUPABASE_URL em formato inválido nos Secrets.")
        st.code(f'SUPABASE_URL = "{url}"')
        st.stop()

    return f"{url}/rest/v1/{tabela}"


def supabase_get(tabela, params=None):
    try:
        resp = requests.get(
            supabase_rest_url(tabela),
            headers=supabase_headers(),
            params=params or {},
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json()
    except Exception as erro:
        url, _ = supabase_config()
        st.error("Erro ao acessar o Supabase.")
        st.warning("O aplicativo tentou acessar este endereço do Supabase pela API REST:")
        st.code(f"{url}/rest/v1/{tabela}")
        st.write(erro)
        st.stop()


def supabase_insert(tabela, rows):
    if not rows:
        return []
    try:
        resp = requests.post(
            supabase_rest_url(tabela),
            headers=supabase_headers(),
            data=json.dumps(rows, ensure_ascii=False),
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json() if resp.text else []
    except Exception as erro:
        url, _ = supabase_config()
        st.error(f"Erro ao inserir dados na tabela {tabela}.")
        st.code(f"{url}/rest/v1/{tabela}")
        try:
            st.write("Resposta do Supabase:", resp.text)
        except Exception:
            pass
        st.write(erro)
        st.stop()


def supabase_update(tabela, dados, coluna, valor):
    try:
        params = {coluna: f"eq.{valor}"}
        resp = requests.patch(
            supabase_rest_url(tabela),
            headers=supabase_headers(),
            params=params,
            data=json.dumps(dados, ensure_ascii=False),
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json() if resp.text else []
    except Exception as erro:
        url, _ = supabase_config()
        st.error(f"Erro ao atualizar dados na tabela {tabela}.")
        st.code(f"{url}/rest/v1/{tabela}")
        st.write(erro)
        st.stop()


def supabase_upsert(tabela, row, on_conflict):
    try:
        headers = supabase_headers()
        headers["Prefer"] = "resolution=merge-duplicates,return=representation"
        params = {"on_conflict": on_conflict}
        resp = requests.post(
            supabase_rest_url(tabela),
            headers=headers,
            params=params,
            data=json.dumps(row, ensure_ascii=False),
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json() if resp.text else []
    except Exception as erro:
        url, _ = supabase_config()
        st.error(f"Erro ao gravar dados na tabela {tabela}.")
        st.code(f"{url}/rest/v1/{tabela}")
        st.write(erro)
        st.stop()


def supabase_upsert_many(tabela, rows, on_conflict="id"):
    if not rows:
        return []
    try:
        headers = supabase_headers()
        headers["Prefer"] = "resolution=merge-duplicates,return=representation"
        params = {"on_conflict": on_conflict}
        resp = requests.post(
            supabase_rest_url(tabela),
            headers=headers,
            params=params,
            data=json.dumps(rows, ensure_ascii=False),
            timeout=30,
        )
        resp.raise_for_status()
        return resp.json() if resp.text else []
    except Exception as erro:
        url, _ = supabase_config()
        st.error(f"Erro ao gravar dados na tabela {tabela}.")
