# ============================================================
# CACHE LEVE DE SESSÃO
# ============================================================

def cache_sessao_get(chave, ttl_segundos=120):
    cache = st.session_state.setdefault("_cache_leve_siga_cor", {})
    item = cache.get(chave)

    if not item:
        return None

    try:
        criado = item.get("criado_em", 0)
        agora = int(datetime.now(timezone.utc).timestamp())
        if agora - criado > ttl_segundos:
            cache.pop(chave, None)
            return None
        return item.get("valor")
    except Exception:
        cache.pop(chave, None)
        return None


def cache_sessao_set(chave, valor):
    cache = st.session_state.setdefault("_cache_leve_siga_cor", {})
    cache[chave] = {
        "valor": valor,
        "criado_em": int(datetime.now(timezone.utc).timestamp()),
    }
    return valor


def cache_sessao_limpar(*chaves):
    if not chaves:
        st.session_state.pop("_cache_leve_siga_cor", None)
        st.session_state.pop("_secoes_atendimento_cache", None)
        return

    cache = st.session_state.setdefault("_cache_leve_siga_cor", {})
    for chave in chaves:
        cache.pop(chave, None)

    if "secoes_atendimento" in chaves:
        st.session_state.pop("_secoes_atendimento_cache", None)


def cache_sessao_limpar_dados():
    cache_sessao_limpar(
        "usuarios",
        "atendimentos",
        "assuntos_rows",
        "usuarios_logados",
        "base_conhecimento",
        "modelos_resposta",
        "secoes_atendimento",
    )



def usuarios():
    cached = cache_sessao_get("usuarios", ttl_segundos=180)
    if cached is not None:
        return cached

    rows = supabase_get("usuarios", {"select": "*", "order": "id.asc"})
    dados = [usuario_db_para_app(row) for row in (rows or [])]
    return cache_sessao_set("usuarios", dados)


def salvar_usuarios(lista):
    criar_backup_automatico("antes_salvar_usuarios")
    rows = [usuario_app_para_db(u) for u in lista]
    rows = [r for r in rows if r.get("email")]
    if rows:
        for r in rows:
            r.pop("id", None)
        try:
            supabase_upsert_many("usuarios", rows, on_conflict="email")
        except Exception:
            # Compatibilidade com banco antigo sem coluna zona_eleitoral.
            rows_basicos = []
            for r in rows:
                rb = dict(r)
                rb.pop("zona_eleitoral", None)
                rows_basicos.append(rb)
            supabase_upsert_many("usuarios", rows_basicos, on_conflict="email")
        supabase_delete_not_in("usuarios", "email", [r.get("email") for r in rows])
    cache_sessao_limpar("usuarios", "usuarios_logados")
    criar_backup_automatico("apos_salvar_usuarios")


def atendimentos():
    cached = cache_sessao_get("atendimentos", ttl_segundos=180)
    if cached is not None:
        return cached

    rows = supabase_get("atendimentos", {"select": "*", "order": "id.asc"})
    dados = [atendimento_db_para_app(row) for row in (rows or [])]
    return cache_sessao_set("atendimentos", dados)


def salvar_atendimentos(lista):
    criar_backup_automatico("antes_salvar_atendimentos")
    rows = [atendimento_app_para_db(a) for a in lista]
    rows = [r for r in rows if r.get("assunto") or r.get("descricao") or r.get("origem")]

    if rows:
        # Grava/atualiza primeiro. Somente depois remove registros antigos.
        supabase_upsert_many("atendimentos", rows, on_conflict="id")
        ids = [r.get("id") for r in rows if r.get("id") not in ("", None)]
        if ids:
            supabase_delete_not_in("atendimentos", "id", ids)
    else:
        supabase_delete_all("atendimentos")

    cache_sessao_limpar("atendimentos", "usuarios_logados")
    criar_backup_automatico("apos_salvar_atendimentos")


def excluir_atendimento_por_id(id_atendimento):
    lista = atendimentos()
    nova_lista = [a for a in lista if int(a.get("id", -1)) != int(id_atendimento)]
    if len(nova_lista) == len(lista):
        return False
    salvar_atendimentos(nova_lista)
    return True



def assunto_rows():
    cached = cache_sessao_get("assuntos_rows", ttl_segundos=300)
    if cached is not None:
        return cached

    # Busca todos os assuntos. O filtro de ativo é feito em Python para evitar
    # inconsistências caso algum registro antigo esteja sem o campo ativo.
    rows = supabase_get("assuntos", {"select": "*", "order": "secao.asc,nome.asc"})
    registros = []

    for row in (rows or []):
        if row.get("ativo") is False:
            continue

        nome = str(row.get("nome") or "").strip()
        if not nome:
            continue

        tipologia = normalizar_tipologia_assunto(row.get("categoria"), nome)
        registros.append({
            "id": row.get("id"),
            "nome": nome,
            "secao": normalizar_secao(row.get("secao") or "SEPRO"),
            "categoria": tipologia,
            "tipologia": tipologia,
            "subcategoria": row.get("subcategoria") or "",
            "ordem": row.get("ordem") or 0,
            "ativo": True,
        })

    if not registros:
        registros = [
            {
                "nome": nome,
                "secao": "SEPRO",
                "categoria": normalizar_tipologia_assunto(None, nome),
                "tipologia": normalizar_tipologia_assunto(None, nome),
                "ativo": True,
            }
            for nome in ASSUNTOS_PADRAO
        ]
        salvar_assuntos_registros(registros)

    registros = sorted(
        registros,
        key=lambda r: (
            r.get("secao", "SEPRO"),
            0 if r.get("nome") == "Não informado" else 1,
            str(r.get("nome", "")).casefold()
        )
    )
    return cache_sessao_set("assuntos_rows", registros)



def tipologia_do_assunto(nome_assunto, secao=None):
    secao_norm = normalizar_secao(secao) if secao else None
    nome_norm = str(nome_assunto or "").strip().casefold()

    for r in assunto_rows():
        if str(r.get("nome", "")).strip().casefold() != nome_norm:
            continue
        if secao_norm and normalizar_secao(r.get("secao")) != secao_norm:
            continue
        return normalizar_tipologia_assunto(r.get("tipologia") or r.get("categoria"), r.get("nome"))

    return normalizar_tipologia_assunto(None, nome_assunto)

def assuntos(secao=None):
    registros = assunto_rows()
    secao_norm = normalizar_secao(secao) if secao else None

    lista = []
    for r in registros:
        nome = str(r.get("nome", "")).strip()
        if not nome:
            continue

        if nome == "Não informado":
            continue

        if secao_norm is None or normalizar_secao(r.get("secao")) == secao_norm:
            lista.append(nome)

    lista = sorted(set(lista), key=lambda x: x.casefold())
    return ["Não informado"] + lista


def salvar_assuntos_registros(registros):
    criar_backup_automatico("antes_salvar_assuntos")
    supabase_delete_all("assuntos")

    normalizados = []
    vistos = set()

    for r in registros:
        if isinstance(r, dict):
            nome = str(r.get("nome") or "").strip()
            secao = normalizar_secao(r.get("secao") or "SEPRO")
            tipologia = normalizar_tipologia_assunto(r.get("tipologia") or r.get("categoria"), nome)
            subcategoria = str(r.get("subcategoria") or "").strip()
            ordem = int(r.get("ordem") or 0)
        else:
            nome = str(r or "").strip()
            secao = "SEPRO"
            tipologia = normalizar_tipologia_assunto(None, nome)
            subcategoria = ""
            ordem = 0

        if not nome:
            continue

        chave = (nome.casefold(), secao)
        if chave in vistos:
            continue
        vistos.add(chave)

        normalizados.append({
            "nome": nome,
            "secao": secao,
            "categoria": tipologia,
            "subcategoria": subcategoria,
            "ordem": ordem,
            "ativo": True,
            "criado_em": agora_iso(),
        })

    if not any(r["nome"] == "Não informado" for r in normalizados):
        normalizados.append({
            "nome": "Não informado",
            "secao": "SEPRO",
            "categoria": "Não classificado",
            "subcategoria": "",
            "ordem": 0,
            "ativo": True,
            "criado_em": agora_iso(),
        })

    normalizados = sorted(
        normalizados,
        key=lambda r: (0 if r["nome"] == "Não informado" else 1, r["secao"], r["nome"].casefold())
    )

    if normalizados:
        try:
            supabase_insert("assuntos", normalizados)
        except Exception:
            # Compatibilidade com bancos antigos sem colunas categoria/subcategoria/ordem.
            # Nesse caso, o assunto permanece cadastrado, mas a tipologia só será persistida
            # após a migração opcional da tabela assuntos.
            basicos = [
                {
                    "nome": r.get("nome"),
                    "secao": r.get("secao"),
                    "ativo": r.get("ativo", True),
                    "criado_em": r.get("criado_em", agora_iso()),
                }
                for r in normalizados
            ]
            supabase_insert("assuntos", basicos)
    cache_sessao_limpar("assuntos_rows")
    criar_backup_automatico("apos_salvar_assuntos")


def salvar_assuntos(lista):
    registros = []
    for item in lista:
        if isinstance(item, dict):
            registros.append(item)
        else:
            registros.append({
                "nome": item,
                "secao": "SEPRO",
                "categoria": normalizar_tipologia_assunto(None, item),
                "tipologia": normalizar_tipologia_assunto(None, item),
                "ativo": True,
            })
    salvar_assuntos_registros(registros)



def registrar_usuario_logado(usuario):
    """
    Registra ou atualiza a sessão ativa do usuário.
    Usa apenas colunas básicas da tabela sessoes para compatibilidade com o banco atual.
    """
    if not usuario:
        return

    email = normalizar_email(usuario.get("email"))
    if not email:
        return

    row = {
        "email": email,
        "nome": usuario.get("nome", email),
        "perfil": usuario.get("perfil", "Usuário"),
        "ativo": True,
        "ultimo_login": agora_iso(),
        "ultimo_logout": None,
    }

    try:
        supabase_upsert("sessoes", row, "email")
        cache_sessao_limpar("usuarios_logados")
    except Exception:
        # Não impede o login se o registro de presença falhar.
        pass



def atualizar_presenca_usuario_logado():
    """
    Atualiza o horário da sessão do usuário atualmente logado.
    Usa apenas colunas básicas da tabela sessoes para evitar erro 400 por coluna inexistente.
    """
    usuario = usuario_logado()
    if not usuario:
        return

    email = normalizar_email(usuario.get("email"))
    if not email:
        return

    try:
        supabase_upsert(
            "sessoes",
            {
                "email": email,
                "nome": usuario.get("nome", email),
                "perfil": usuario.get("perfil", "Usuário"),
                "ativo": True,
                "ultimo_login": agora_iso(),
                "ultimo_logout": None,
            },
            "email"
        )
        cache_sessao_limpar("usuarios_logados")
    except Exception:
        # Não interrompe o sistema se a atualização de presença falhar.
        # O painel ainda contará o usuário atual pela sessão local.
        pass



def remover_usuario_logado():
    usuario = usuario_logado()
    if not usuario:
        return

    email = normalizar_email(usuario.get("email"))
    if not email:
        return

    try:
        supabase_update("sessoes", {"ativo": False, "ultimo_logout": agora_iso()}, "email", email)
        cache_sessao_limpar("usuarios_logados")
    except Exception:
        pass



def sessao_esta_ativa(row):
    """
    Considera ativo apenas quem teve atualização de presença dentro da janela definida.
    Usa ultimo_login, pois a tabela sessoes pode não possuir a coluna ultimo_ping.
    """
    if not row or not row.get("ativo", False):
        return False

    ultimo = obter_data_hora_atendimento(row.get("ultimo_login"))
    if not ultimo:
        return False

    limite = agora_brasilia() - timedelta(minutes=SESSAO_ATIVA_MINUTOS)
    return ultimo >= limite



def usuarios_logados():
    """
    Retorna usuários ativos sem fazer limpeza automática no banco.
    Não depende da coluna ultimo_ping.
    Garante também a inclusão do usuário da sessão atual para não exibir zero indevidamente.
    """
    cached = cache_sessao_get("usuarios_logados", ttl_segundos=30)
    if cached is not None:
        return cached

    rows = supabase_get_silencioso(
        "sessoes",
        {"select": "email,nome,ultimo_login,ativo", "ativo": "eq.true", "order": "ultimo_login.desc"}
    ) or []

    ativos = [row for row in rows if sessao_esta_ativa(row)]

    atual = usuario_logado() or {}
    email_atual = normalizar_email(atual.get("email"))
    if email_atual and not any(normalizar_email(r.get("email")) == email_atual for r in ativos):
        ativos.insert(0, {
            "email": email_atual,
            "nome": atual.get("nome", email_atual),
            "ultimo_login": agora_iso(),
            "ativo": True,
        })

    return cache_sessao_set("usuarios_logados", ativos)



def email_institucional(email):
    return normalizar_email(email).endswith(DOMINIO_INSTITUCIONAL)


def usuario_logado():
    return st.session_state.get("usuario")


def eh_admin():
    u = usuario_logado()
    if not u:
        return False

    perfil = perfil_normalizado(u.get("perfil"))

    return perfil in (
        "Administrador geral",
        "Administrador",
    )


def usuarios_ativos_validados():
    return [
        u for u in usuarios()
        if u.get("ativo", True) and u.get("validado", False)
    ]


def nomes_usuarios_ativos():
    nomes = []
    for u in usuarios_ativos_validados():
        nome = u.get("nome") or u.get("email")
        if nome:
            nomes.append(nome)
    return sorted(set(nomes))



def servidores_por_secao_dropdown(secao, atual=""):
    """
    Lista usuários ativos/validados cadastrados para a seção informada.
    Usada no campo Servidor responsável da fase Em atendimento.
    """
    secao_norm = normalizar_secao(secao)
    atual = str(atual or "").strip()
    opcoes = ["Não informado"]

    try:
        for u in usuarios_ativos_validados():
            nome = str(u.get("nome") or u.get("email") or "").strip()
            if not nome:
                continue

            secao_usuario = normalizar_secao(u.get("secao_operador") or u.get("secao") or "")
            perfil = perfil_normalizado(u.get("perfil") or "")

            # Administradores podem aparecer como opção geral; operadores/chefias entram pela seção.
            if secao_usuario == secao_norm or perfil in ("Administrador geral", "Administrador"):
                if nome not in opcoes:
                    opcoes.append(nome)
    except Exception:
        pass

    if atual and atual not in opcoes:
        opcoes.insert(1, atual)

    return opcoes




def proximo_id(lista):
    if not lista:
        return 1
    ids = []
    for item in lista:
        try:
            ids.append(int(item.get("id", 0)))
        except Exception:
            pass
    return max(ids or [0]) + 1


def status_badge(status):
    texto = str(status or "").strip()
    texto_cf = texto.casefold()

    if texto == STATUS_CADASTRADO:
        return '<span class="status-pill triagem">● Triagem</span>'
    if texto == STATUS_EM_ATENDIMENTO:
        return '<span class="status-pill em">● Em atendimento</span>'
    if texto == STATUS_REALIZADO:
        return '<span class="status-pill realizado">● Atendimento realizado</span>'
    if "zel" in texto_cf and "pendente" in texto_cf:
        return '<span class="status-pill zel">● Pendente Zel</span>'
    if "vencido" in texto_cf or "devolvido" in texto_cf:
        return f'<span class="status-pill alerta">● {html.escape(texto)}</span>'
    if not texto:
        return '<span class="status-pill neutro">● Não informado</span>'

    return f'<span class="status-pill neutro">● {html.escape(texto)}</span>'



