def render_card_navegacao(icone, titulo, descricao, texto_botao, destino, key, categoria="atendimento"):
    categoria = str(categoria or "atendimento").strip().casefold()
    if categoria not in ("atendimento", "conhecimento", "gestao", "admin"):
        categoria = "atendimento"

    rotulo = {
        "atendimento": "Atendimento",
        "conhecimento": "Conhecimento",
        "gestao": "Gestão",
        "admin": "Administração",
    }.get(categoria, "Atendimento")

    st.markdown(
        f"""
        <div class="siga-card-nav card-{categoria}">
            <div class="siga-card-tag">{html.escape(rotulo)}</div>
            <div class="siga-card-title"><span class="siga-card-icon">{ui_icon(icone)}</span>{html.escape(str(titulo))}</div>
            <div class="siga-card-desc">{html.escape(str(descricao))}</div>
            <div class="siga-card-arrow">›</div>
        </div>
        """,
        unsafe_allow_html=True,
    )
    botao_navegacao(texto_botao, destino, key)


def render_grupo_menu(titulo, categoria, cards):
    if not cards:
        return

    st.markdown(
        f'<div class="siga-group-title {html.escape(categoria)}"><span></span>{html.escape(titulo)}</div>',
        unsafe_allow_html=True
    )

    colunas = st.columns(min(len(cards), 4))
    for idx, card in enumerate(cards):
        with colunas[idx % len(colunas)]:
            render_card_navegacao(*card, categoria=categoria)









def estilo_status_tabela_rapida(row):
    status = str(row.get("Status", "")).casefold()

    if "em atendimento" in status:
        estilo = "background-color: #FFF4DE; color: #7A4B00; font-weight: 700;"
    elif "realizado" in status:
        estilo = "background-color: #E8F5E9; color: #1B5E20; font-weight: 700;"
    elif "triagem" in status:
        estilo = "background-color: #E3F2FD; color: #0D47A1; font-weight: 700;"
    elif "devolvido" in status:
        estilo = "background-color: #FDECEA; color: #B00020; font-weight: 700;"
    elif "pendente" in status:
        estilo = "background-color: #F3E8FF; color: #4A148C; font-weight: 700;"
    else:
        estilo = "background-color: #F8FAFC; color: #0F172A;"

    return [estilo if col == "Status" else "" for col in row.index]


def exibir_tabela_rapida_status_colorido(df):
    if df is None or df.empty:
        st.info("Nenhum atendimento cadastrado para exibição rápida.")
        return

    try:
        st.dataframe(
            df.style.apply(estilo_status_tabela_rapida, axis=1),
            use_container_width=True,
            hide_index=True,
        )
    except Exception:
        st.dataframe(df, use_container_width=True, hide_index=True)




def pagina_por_status_atendimento(status):
    status = str(status or "")
    if status == STATUS_EM_ATENDIMENTO:
        return "Em atendimento"
    if status == STATUS_REALIZADO:
        return "Atendimento realizado"
    if status == STATUS_CADASTRADO:
        return "Triagem"
    return "Base geral"


def abrir_atendimento_por_status(atendimento):
    st.session_state["atendimento_foco_id"] = int(atendimento.get("id"))
    st.session_state["atendimento_foco_status"] = atendimento.get("status")
    ir_para_pagina(pagina_por_status_atendimento(atendimento.get("status")))
    st.rerun()


def atendimento_em_foco_id():
    try:
        return int(st.session_state.get("atendimento_foco_id")) if st.session_state.get("atendimento_foco_id") else None
    except Exception:
        return None



def registrar_mensagem_sistema(tipo, texto):
    st.session_state["mensagem_sistema_tipo"] = tipo
    st.session_state["mensagem_sistema_texto"] = texto


def exibir_mensagem_sistema():
    texto = st.session_state.pop("mensagem_sistema_texto", "")
    tipo = st.session_state.pop("mensagem_sistema_tipo", "")
    if not texto:
        return
    if tipo == "success":
        st.success(texto)
    elif tipo == "warning":
        st.warning(texto)
    elif tipo == "error":
        st.error(texto)
    else:
        st.info(texto)


def limpar_atendimento_em_foco():
    st.session_state.pop("atendimento_foco_id", None)
    st.session_state.pop("atendimento_foco_status", None)


def render_tabela_rapida_com_acao(lista, limite=15):
    recentes = sorted(lista or [], key=lambda x: int(x.get("id", 0)), reverse=True)[:limite]

    if not recentes:
        st.info("Nenhum atendimento cadastrado para exibição rápida.")
        return

    df = dataframe_atendimentos_rapidos(recentes, limite=limite)
    exibir_tabela_rapida_status_colorido(df)

    st.markdown("#### Abrir atendimento")
    st.caption("Selecione um atendimento da lista acima e clique em abrir. O sistema irá para a página correspondente ao status atual.")

    opcoes = [
        f"{a.get('id')} - {a.get('status')} - {a.get('origem') or 'sem origem'} - {a.get('assunto') or 'sem assunto'}"
        for a in recentes
    ]

    col1, col2 = st.columns([4, 1])
    with col1:
        escolhido = st.selectbox(
            "Atendimento",
            opcoes,
            key="abrir_atendimento_rapido_select",
            label_visibility="collapsed",
        )

    with col2:
        if st.button("Abrir", key="abrir_atendimento_rapido_btn", use_container_width=True):
            atendimento_id = int(str(escolhido).split(" - ")[0])
            atendimento = next((a for a in recentes if int(a.get("id")) == atendimento_id), None)
            if atendimento:
                abrir_atendimento_por_status(atendimento)



def buscar_atendimentos_texto(lista, termo):
    termo = str(termo or "").strip().casefold()
    if not termo:
        return lista

    campos = [
        "id",
        "data",
        "status",
        "secao",
        "servidor",
        "fonte",
        "assunto",
        "zona_eleitoral",
        "origem",
        "prioridade",
        "complexidade",
        "protocolo",
        "descricao",
        "observacoes",
        "providencia_adotada",
        "situacao_validacao",
    ]

    filtrados = []
    for a in lista or []:
        texto = " ".join([str(a.get(c, "")) for c in campos]).casefold()
        if termo in texto:
            filtrados.append(a)

    return filtrados


def dataframe_atendimentos_rapidos(lista, limite=12):
    linhas = []
    for a in sorted(lista or [], key=lambda x: int(x.get("id", 0)), reverse=True)[:limite]:
        linhas.append({
            "ID": a.get("id"),
            "Data": data_para_exibir(a.get("data")),
            "Quem originou": a.get("origem") or "",
            "Zona eleitoral": a.get("zona_eleitoral") or "Não informado",
            "Assunto": a.get("assunto") or "Não informado",
            "Responsável": a.get("servidor") or "Não informado",
            "Status": a.get("status") or "",
            "Atualizado": formatar_data_hora_brasilia(a.get("atualizado_em")) if a.get("atualizado_em") else "",
        })
    return pd.DataFrame(linhas)


def bloco_novos_atendimentos_inicio():
    st.markdown("### Visualização rápida dos atendimentos cadastrados")
    lista = filtrar_lista_por_perfil(atendimentos())
    recentes = [
        a for a in lista
        if a.get("status") in (STATUS_EM_ATENDIMENTO, STATUS_REALIZADO, STATUS_CADASTRADO)
    ]
    render_tabela_rapida_com_acao(recentes, limite=15)

