def fonte_unica_zel_rows():
    """
    Fonte única da Zel: Base de Conhecimento institucional.
    """
    fontes = []
    try:
        rows = base_conhecimento_rows(incluir_superadas=False)
    except Exception:
        rows = []

    for b in rows or []:
        try:
            codigo = codigo_base_conhecimento(b)
        except Exception:
            codigo = str(b.get("id") or "")

        conteudo = "\n".join([
            f"Código: {codigo}",
            f"Seção: {normalizar_secao(b.get('secao') or 'SEPRO')}",
            f"Assunto: {b.get('assunto') or b.get('categoria') or 'Não informado'}",
            f"Resumo da dúvida: {b.get('resumo_duvida') or ''}",
            f"Orientação adotada: {b.get('orientacao_adotada') or ''}",
            f"Fundamento normativo: {b.get('fundamento_normativo') or ''}",
        ]).strip()

        if not conteudo:
            continue

        fontes.append({
            "id": b.get("id"),
            "titulo": f"Base de Conhecimento {codigo}",
            "secao": normalizar_secao(b.get("secao") or "SEPRO"),
            "assunto": b.get("assunto") or b.get("categoria") or "Não informado",
            "tipo_fonte": "Base de Conhecimento",
            "referencia": f"BASE:{b.get('id') or codigo}",
            "conteudo_texto": conteudo,
            "nome_arquivo": "",
            "ativo": True,
            "validado": True,
            "origem_base_conhecimento": True,
        })
    return fontes


def cadastrar_base_conhecimento_unica(titulo, secao, assunto, resumo_duvida, orientacao_adotada, fundamento_normativo, atendimento_id=None):
    """
    Cadastro único de conhecimento institucional. Tudo que entra aqui vira fonte da Zel.
    """
    usuario = usuario_logado() or {}
    row = {
        "secao": normalizar_secao(secao),
        "assunto": assunto or "Não informado",
        "categoria": assunto or "Não informado",
        "resumo_duvida": str(resumo_duvida or titulo or "").strip(),
        "orientacao_adotada": str(orientacao_adotada or "").strip(),
        "fundamento_normativo": str(fundamento_normativo or "").strip(),
        "atendimento_id": atendimento_id,
        "ativo": True,
        "superada": False,
        "criado_por_email": usuario.get("email", ""),
        "criado_por_nome": usuario.get("nome", ""),
        "criado_em": agora_iso(),
        "atualizado_em": agora_iso(),
    }

    try:
        ok, msg, dados = supabase_insert_diagnostico("base_conhecimento", [row])
        if ok:
            return dados if dados is not None else []
    except Exception as e:
        msg = str(e)

    # Fallback para instalações com colunas mais simples
    row_simples = dict(row)
    for k in ["categoria", "atendimento_id", "ativo", "superada", "criado_por_email", "criado_por_nome", "atualizado_em"]:
        row_simples.pop(k, None)

    try:
        ok, msg, dados = supabase_insert_diagnostico("base_conhecimento", [row_simples])
        if ok:
            return dados if dados is not None else []
        st.error("Não foi possível cadastrar a Base de Conhecimento.")
        st.code(str(msg))
        return None
    except Exception as e:
        st.error("Não foi possível cadastrar a Base de Conhecimento.")
        st.code(str(e))
        return None



def fontes_relevantes_zel(atendimento=None, pergunta_livre="", limite=10):
    """
    A Zel busca exclusivamente na Base de Conhecimento.
    """
    termos = termos_do_atendimento_para_ia(atendimento, pergunta_livre)
    secao = normalizar_secao((atendimento or {}).get("secao") or "SEPRO")
    assunto = str((atendimento or {}).get("assunto") or "").strip()

    candidatos = []
    for f in fonte_unica_zel_rows():
        texto = fonte_zel_para_texto(f) if "fonte_zel_para_texto" in globals() else str(f.get("conteudo_texto") or "")
        score = pontuar_relevancia_controlada(texto, termos)

        if assunto and assunto.casefold() in texto.casefold():
            score += 8
        if secao and normalizar_secao(f.get("secao") or secao) == secao:
            score += 3

        if score > 0:
            candidatos.append((score, f))

    candidatos = sorted(candidatos, key=lambda x: x[0], reverse=True)
    return [f for score, f in candidatos[:limite]]


def fontes_base_conhecimento_como_fonte_zel(atendimento=None, pergunta_livre="", limite=4):
    """
    Permite usar entendimentos já validados da base de conhecimento como fonte institucional.
    A Zel não usa atendimento de outras zonas como fonte; usa apenas fontes_zel e base_conhecimento institucional.
    """
    termos = termos_do_atendimento_para_ia(atendimento, pergunta_livre)
    secao = normalizar_secao((atendimento or {}).get("secao") or (usuario_logado() or {}).get("secao") or "SEPRO")
    assunto = str((atendimento or {}).get("assunto") or "").strip()

    candidatos = []
    for b in base_conhecimento_rows(incluir_superadas=False):
        texto = " ".join([
            str(b.get("codigo_cadastro") or ""),
            str(b.get("secao") or ""),
            str(b.get("assunto") or b.get("categoria") or ""),
            str(b.get("resumo_duvida") or ""),
            str(b.get("orientacao_adotada") or ""),
            str(b.get("fundamento_normativo") or ""),
        ])
        score = pontuar_relevancia_controlada(texto, termos)
        if assunto and assunto.casefold() in texto.casefold():
            score += 5
        if secao and normalizar_secao(b.get("secao") or secao) == secao:
            score += 2
        if score > 0:
            candidatos.append((score, b))

    candidatos = sorted(candidatos, key=lambda x: x[0], reverse=True)
    return [b for score, b in candidatos[:limite]]


def codigo_base_ia(base):
    try:
        return codigo_base_conhecimento(base)
    except Exception:
        if base.get("codigo_cadastro"):
            return str(base.get("codigo_cadastro"))
        if base.get("id"):
            return f"BC-{int(base.get('id')):06d}"
        return "Base sem código"




def resumo_fontes_zel(fontes, bases=None):
    partes = []
    for f in fontes or []:
        titulo = f.get("titulo") or f.get("referencia") or "Base de Conhecimento"
        partes.append(f"Base de Conhecimento: {titulo}")
    return ", ".join(partes)


def zel_normalizar_texto(texto):
    texto = str(texto or "").casefold()
    texto = texto.replace("\r", "\n")
    texto = re.sub(r"[^\w\sáàâãéèêíïóôõöúçñº°.-]", " ", texto, flags=re.IGNORECASE)
    texto = re.sub(r"\s+", " ", texto).strip()
    return texto


def zel_tokens_pergunta(pergunta):
    texto = zel_normalizar_texto(pergunta)
    stop = {
        "qual", "quais", "como", "para", "pela", "pelo", "pelas", "pelos", "sobre",
        "entre", "dentro", "fora", "esse", "essa", "este", "esta", "isso", "isto",
        "mais", "menos", "muito", "pouco", "deve", "pode", "ser", "sao", "são",
        "das", "dos", "uma", "umas", "uns", "com", "sem", "por", "que", "eleitoral",
        "eleitorais", "pra", "está", "esta", "seria", "fazer", "após", "apos"
    }
    tokens = []
    for p in texto.split():
        p = p.strip(" .,-;:()[]{}")
        if len(p) >= 4 and p not in stop and p not in tokens:
            tokens.append(p)

    extras = []
    joined = " ".join(tokens + [texto])

    if "transito" in joined or "trânsito" in joined:
        extras += ["trânsito em julgado", "transito em julgado", "irrecorrível", "irrecorrivel", "definitivo"]
    if "pagamento" in joined or "pagar" in joined or "pago" in joined:
        extras += ["pagamento", "pagar", "recolhimento", "recolher", "baixa", "quitação", "quitacao"]
    if "multa" in joined:
        extras += ["multa", "multas", "sanção pecuniária", "sanções pecuniárias"]
    if "administr" in joined:
        extras += ["administrativo-eleitoral", "administrativo eleitoral", "esfera administrativa", "multa administrativo-eleitoral"]
    if "judicial" in joined or "sentença" in joined or "sentenca" in joined:
        extras += ["multa judicial eleitoral", "cumprimento definitivo de sentença", "sentença", "sentenca"]
    if "intima" in joined:
        extras += ["intimação", "intimado", "intimada", "intimar"]
    if "prazo" in joined:
        extras += ["prazo", "dias", "úteis", "uteis"]
    if "execu" in joined or "cobran" in joined or "cumprimento" in joined:
        extras += ["execução", "execucao", "cumprimento", "cobrança", "cobranca", "devedor"]
    if "parcel" in joined:
        extras += ["parcelamento", "parcelar", "parcelas", "requerimento"]
    if "que é" in joined or "o que e" in joined or "conceito" in joined or "defina" in joined or "significa" in joined:
        extras += ["considera-se", "conceito", "definição", "definicao", "sanção pecuniária", "descumprimento de obrigação eleitoral"]

    for e in extras:
        if e not in tokens:
            tokens.append(e)

    return tokens[:65]


def zel_dividir_blocos_normativos(texto):
    texto = str(texto or "").replace("\r", "\n")
    texto = re.sub(r"\n{3,}", "\n\n", texto)
    padrao = re.compile(
        r"(?=^\s*(?:LIVRO|T[ÍI]TULO|CAP[ÍI]TULO|SE[ÇC][ÃA]O|SUBSE[ÇC][ÃA]O|Art\.?\s*\d+[º°]?|§\s*\d+|Parágrafo único))",
        re.IGNORECASE | re.MULTILINE
    )
    partes = [p.strip() for p in padrao.split(texto) if p and p.strip()]
    if len(partes) <= 1:
        partes = [p.strip() for p in re.split(r"\n\s*\n", texto) if p and p.strip()]

    blocos = []
    buffer = ""
    for p in partes:
        if len(buffer) < 350:
            buffer = (buffer + "\n" + p).strip()
        else:
            blocos.append(buffer)
            buffer = p
    if buffer:
        blocos.append(buffer)
    return blocos


def zel_agente_identificar_intencao(pergunta):
    p = zel_normalizar_texto(pergunta)

    if p.startswith("o que e ") or p.startswith("o que é ") or "conceito" in p or "defina" in p or "significa" in p:
        return "conceito"

    if "diferen" in p or "disting" in p or "compar" in p:
        return "diferenciacao"

    if "prazo" in p or "intima" in p or "quantos dias" in p:
        return "prazo"

    if ("o que fazer" in p or "providencia" in p or "providência" in p or "após" in p or "apos" in p) and ("multa" in p or "pagamento" in p or "transito" in p or "trânsito" in p):
        return "providencia_pos_pagamento_ou_transito"

    if "como" in p or "proced" in p or "execu" in p or "cobran" in p or "tramita" in p or "cumprimento" in p:
        return "procedimento"

    if "parcel" in p:
        return "parcelamento"

    return "orientacao"


def zel_agente_classificar(atendimento=None, pergunta_livre=""):
    pergunta = str(pergunta_livre or (atendimento or {}).get("descricao") or "").strip()
    assunto = str((atendimento or {}).get("assunto") or "").strip()
    secao = normalizar_secao((atendimento or {}).get("secao") or "SEPRO") if "normalizar_secao" in globals() else str((atendimento or {}).get("secao") or "SEPRO")
    texto = zel_normalizar_texto(" ".join([pergunta, assunto]))

    intencao = zel_agente_identificar_intencao(pergunta)
    tema = "geral"
    risco = "medio"
    exige_prazo_expresso = intencao == "prazo"

    if "multa" in texto and ("judicial" in texto or "sentenca" in texto or "sentença" in texto or "cumprimento" in texto or "trânsito" in texto or "transito" in texto):
        tema = "multa_judicial"
        risco = "alto"
    elif "multa" in texto and "administr" in texto:
        tema = "multa_administrativa"
        risco = "alto"
    elif "parcel" in texto and "multa" in texto:
        tema = "parcelamento_multa"
        risco = "alto"
    elif "multa" in texto:
        tema = "multa"
        risco = "alto"
    elif "cadin" in texto:
        tema = "cadin"
        risco = "alto"
    elif "serasa" in texto or "serasajud" in texto:
        tema = "serasajud"
        risco = "alto"
    elif "filiacao" in texto or "filiação" in texto:
        tema = "filiacao"
        risco = "alto"
    elif "propaganda" in texto or "poder de policia" in texto or "poder de polícia" in texto:
        tema = "propaganda_poder_policia"
        risco = "alto"

    if exige_prazo_expresso:
        risco = "alto"

    if not pergunta:
        risco = "critico"

    return {
        "pergunta": pergunta,
        "assunto": assunto or "Não informado",
        "secao": secao,
        "tema": tema,
        "intencao": intencao,
        "risco": risco,
        "exige_prazo_expresso": exige_prazo_expresso,
        "tokens": zel_tokens_pergunta(pergunta),
    }


def zel_pontuar_bloco(bloco, contexto):
    bloco_norm = zel_normalizar_texto(bloco)
    pergunta_norm = zel_normalizar_texto(contexto.get("pergunta"))
    tokens = contexto.get("tokens") or []
    tema = contexto.get("tema")
    intencao = contexto.get("intencao")
    exige_prazo = bool(contexto.get("exige_prazo_expresso"))

    score = 0
    for t in tokens:
        t_norm = zel_normalizar_texto(t)
        if t_norm and t_norm in bloco_norm:
            score += 8 if " " in t_norm else 4

    if intencao == "conceito":
        for t in ["considera-se", "conceito", "definição", "definicao", "sanção pecuniária", "sancao pecuniaria", "descumprimento de obrigação eleitoral", "não mais passível de recurso"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 16

    if intencao == "providencia_pos_pagamento_ou_transito":
        for t in ["pagamento", "compensação bancária", "compensacao bancaria", "baixada", "baixa", "extinção", "extincao", "trânsito em julgado", "transito em julgado", "cumprimento definitivo", "art. 12", "art. 25", "art. 26", "art. 31"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 16

    if tema == "multa_administrativa":
        if "multa" not in bloco_norm or "administr" not in bloco_norm:
            score -= 10
        for t in ["multa administrativo-eleitoral", "administrativo-eleitoral", "administrativo eleitoral", "esfera administrativa", "lançamento automático", "lancamento automatico"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 14

    if tema in ("multa_judicial", "multa"):
        for t in ["multa judicial", "cumprimento definitivo de sentença", "sentença", "sentenca", "trânsito em julgado", "transito em julgado", "irrecorrível", "irrecorrivel"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 12

    if tema == "parcelamento_multa" or intencao == "parcelamento":
        for t in ["parcelamento", "parcelas", "requerimento", "título iii", "titulo iii"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 14

    if exige_prazo:
        for t in ["prazo", "dias", "intimação", "intimacao", "intimado", "intimada", "pagamento", "pagar", "devedor"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 14

    if intencao == "procedimento" or "execu" in pergunta_norm or "cobran" in pergunta_norm:
        for t in ["execução", "execucao", "cobrança", "cobranca", "livro ii", "título i", "titulo i", "devedor", "cumprimento"]:
            if zel_normalizar_texto(t) in bloco_norm:
                score += 8

    if intencao not in ("conceito", "providencia_pos_pagamento_ou_transito") and contexto.get("risco") == "alto" and (
        "disposições gerais" in bloco_norm or "art. 1º" in bloco_norm or "art. 2º" in bloco_norm
    ):
        score -= 25

    return score


def zel_extrair_prazos_do_texto(texto):
    texto_original = str(texto or "")
    achados = []
    padroes = [
        r"prazo\s+de\s+.{0,80}?\d+\s*\([^)]+\)\s*dias(?:\s+úteis|\s+uteis)?",
        r"prazo\s+de\s+.{0,80}?\d+\s*dias(?:\s+úteis|\s+uteis)?",
        r"\d+\s*\([^)]+\)\s*dias(?:\s+úteis|\s+uteis)?",
        r"\d+\s*dias(?:\s+úteis|\s+uteis)?",
    ]
    for padrao in padroes:
        for m in re.finditer(padrao, texto_original, flags=re.IGNORECASE):
            trecho = re.sub(r"\s+", " ", m.group(0)).strip()
            if trecho not in achados:
                achados.append(trecho)
    return achados[:5]


def zel_extrair_definicao_multa_administrativa(texto):
    texto = re.sub(r"\s+", " ", str(texto or "")).strip()
    padroes = [
        r"multa administrativo-eleitoral:\s*(.*?)(?=;\s*II\s*-|II\s*-|$)",
        r"multa administrativa:\s*(.*?)(?=;\s*II\s*-|II\s*-|$)",
    ]
    for padrao in padroes:
        m = re.search(padrao, texto, flags=re.IGNORECASE)
        if m:
            definicao = m.group(1).strip(" ;.")
            if definicao:
                return definicao
    return ""


def zel_fonte_row_validada(row):
    if not row:
        return False
    if row.get("ativo", True) is False:
        return False
    if row.get("validado", True) is False:
        return False
    return True


def zel_base_row_validada(row):
    if not row:
        return False
    if row.get("ativo", True) is False:
        return False
    if row.get("superada", False) is True:
        return False
    return True


def zel_agente_buscar_evidencias(contexto, fontes=None, bases=None, limite=None):
    if limite is None:
        limite = ZEL_MAX_EVIDENCIAS

    candidatos = []

    for b in bases or []:
        if not zel_base_row_validada(b):
            continue

        try:
            titulo = codigo_base_ia(b)
        except Exception:
            titulo = str(b.get("codigo_cadastro") or "Base de Conhecimento")

        texto = "\n".join([
            str(b.get("resumo_duvida") or ""),
            str(b.get("orientacao_adotada") or ""),
            str(b.get("fundamento_normativo") or ""),
        ]).strip()

        score = zel_pontuar_bloco(texto, contexto)
        if score >= ZEL_SCORE_MINIMO_EVIDENCIA:
            candidatos.append({
                "tipo": "Base de Conhecimento validada",
                "titulo": titulo,
                "referencia": "",
                "texto": texto,
                "score": score + 8,
            })

    for f in fontes or []:
        if not zel_fonte_row_validada(f):
            continue

        titulo = str(f.get("titulo") or "Documento de apoio").strip()
        referencia = str(f.get("referencia") or "").strip()
        conteudo = str(f.get("conteudo_texto") or "").strip()

        for bloco in zel_dividir_blocos_normativos(conteudo):
            score = zel_pontuar_bloco(bloco, contexto)
            if score >= ZEL_SCORE_MINIMO_EVIDENCIA:
                candidatos.append({
                    "tipo": "Documento de apoio validado",
                    "titulo": titulo,
                    "referencia": referencia,
                    "texto": bloco.strip(),
                    "score": score,
                })

    return sorted(candidatos, key=lambda x: x["score"], reverse=True)[:limite]


def zel_agente_checar_suficiencia(contexto, evidencias):
    if contexto.get("risco") == "critico":
        return False, "O atendimento/pergunta não contém descrição suficiente."

    if not evidencias:
        return False, "Nenhuma Base de Conhecimento validada ou documento de apoio validado apresentou trecho aderente à pergunta."

    texto = zel_normalizar_texto("\n\n".join(e.get("texto") or "" for e in evidencias))
    maior_score = max([e.get("score", 0) for e in evidencias] or [0])

    if maior_score < ZEL_SCORE_MINIMO_EVIDENCIA:
        return False, "A aderência entre a pergunta e os trechos localizados foi insuficiente."

    if contexto.get("exige_prazo_expresso"):
        if maior_score < ZEL_SCORE_MINIMO_PRAZO:
            return False, "A pergunta envolve prazo/intimação/pagamento, mas a evidência não atingiu o nível mínimo de segurança."
        if not zel_extrair_prazos_do_texto(texto):
            return False, "A pergunta envolve prazo, mas nenhum número de dias foi localizado expressamente em base validada."

    if contexto.get("tema") == "multa_administrativa":
        if "multa" not in texto or "administr" not in texto:
            return False, "A pergunta envolve multa administrativa, mas o trecho localizado não confirma esse enquadramento."

    if contexto.get("intencao") == "conceito" and contexto.get("tema") == "multa_administrativa":
        if not ("sanção" in texto or "sancao" in texto or "considera-se" in texto or "descumprimento" in texto):
            return False, "A pergunta pede conceito, mas o trecho localizado não contém definição normativa suficiente."

    return True, "Evidência suficiente."


def zel_agente_bloquear(motivo):
    return (
        "A Zel não encontrou fundamento validado suficiente para responder com segurança.\n\n"
        f"Motivo do bloqueio: {motivo}\n\n"
        "Encaminhamento sugerido:\n"
        "1. não gravar resposta automática;\n"
        "2. verificar se a Base de Conhecimento ou o documento de apoio contém o trecho específico da pergunta;\n"
        "3. cadastrar ou ajustar a Base de Conhecimento com orientação validada;\n"
        "4. submeter a demanda à análise manual da unidade responsável.\n\n"
        "Regra de segurança: a Zel não cria conceito, prazo, rito, requisito ou conclusão jurídica sem fundamento validado correspondente."
    )


def zel_agente_redigir(contexto, evidencias):
    ok, motivo = zel_agente_checar_suficiencia(contexto, evidencias)
    if not ok:
        return zel_agente_bloquear(motivo)

    tema = contexto.get("tema")
    intencao = contexto.get("intencao")
    texto_evidencia = "\n\n".join(e["texto"] for e in evidencias)
    prazos = zel_extrair_prazos_do_texto(texto_evidencia)

    if intencao == "conceito" and tema == "multa_administrativa":
        definicao = zel_extrair_definicao_multa_administrativa(texto_evidencia)
        if not definicao:
            return zel_agente_bloquear("A pergunta pede conceito de multa administrativa, mas a definição normativa não foi extraída com segurança.")

        return (
            "Multa administrativo-eleitoral é a sanção pecuniária imposta em razão de descumprimento de obrigação eleitoral, "
            "decorrente de decisão administrativa ou de lançamento automático em sistema da Justiça Eleitoral, quando não mais passível de recurso na esfera administrativa.\n\n"
            "Em termos práticos, ela se diferencia da multa judicial eleitoral porque nasce de decisão ou registro administrativo da Justiça Eleitoral, e sua cobrança segue o rito próprio das multas administrativo-eleitorais.\n\n"
            "Definição extraída da base validada: " + definicao + "."
        )

    if intencao == "providencia_pos_pagamento_ou_transito":
        return (
            "Após o trânsito em julgado da decisão que determinou o pagamento de multa, a providência depende do enquadramento da multa e da fase em que o processo se encontra.\n\n"
            "Com base nos fundamentos localizados, a unidade deve verificar se a multa é judicial eleitoral ou administrativo-eleitoral, confirmar se houve pagamento e compensação bancária, e então adotar a providência correspondente: registrar/baixar a multa quando quitada, certificar a situação nos autos e, se não houver pagamento ou se ainda houver saldo, prosseguir com os atos de cobrança ou cumprimento previstos na base validada.\n\n"
            "A resposta final deve indicar expressamente o fundamento aplicado ao caso concreto antes do envio à Zona."
        )

    if intencao == "diferenciacao" and tema in ("multa_administrativa", "multa_judicial", "multa"):
        return (
            "A base validada diferencia a multa administrativo-eleitoral da multa judicial eleitoral. "
            "A multa administrativo-eleitoral decorre de decisão administrativa ou lançamento automático em sistema da Justiça Eleitoral, quando não há mais recurso administrativo. "
            "Já a multa judicial eleitoral decorre de decisão judicial irrecorrível por violação ao Código Eleitoral ou às leis eleitorais.\n\n"
            "A consequência prática é que a primeira segue rito de execução próprio das multas administrativas, enquanto a segunda segue cumprimento definitivo de sentença."
        )

    if intencao == "prazo":
        return (
            f"Com base no fundamento validado localizado, o prazo expressamente identificado é: {', '.join(prazos)}.\n\n"
            "Antes do envio, a unidade responsável deve conferir se o dispositivo localizado corresponde exatamente ao caso concreto. "
            "A Zel não fixa prazo por analogia, memória ou inferência; apenas reproduz prazo localizado em base validada."
        )

    if intencao == "procedimento" and tema in ("multa_administrativa", "multa_judicial", "multa"):
        return (
            "Com base no fundamento validado localizado, a cobrança da multa deve seguir o rito correspondente ao seu enquadramento jurídico.\n\n"
            "Resposta sugerida: confirmar se a multa é administrativo-eleitoral ou judicial eleitoral, verificar a definitividade da decisão, identificar corretamente o devedor, conferir pagamento/compensação e adotar os atos de cobrança, baixa ou cumprimento previstos na base validada."
        )

    if intencao == "parcelamento" or tema == "parcelamento_multa":
        return (
            "Com base no fundamento validado localizado, o parcelamento de multa eleitoral deve observar os requisitos, limites e procedimento expressamente previstos na base validada.\n\n"
            "Resposta sugerida: analisar o requerimento conforme os parâmetros da base validada, sem ampliar hipóteses ou dispensar requisitos não previstos."
        )

    return (
        "Com base nos fundamentos validados localizados, há suporte para resposta institucional.\n\n"
        "Resposta sugerida: encaminhar orientação objetiva mencionando apenas o conceito, procedimento, requisito ou conclusão expressamente amparado na Base de Conhecimento ou documento de apoio validado."
    )


def zel_agente_resumir_evidencias(evidencias):
    if not evidencias:
        return "Nenhum fundamento validado específico foi localizado."

    linhas = []
    for i, e in enumerate(evidencias, start=1):
        ref = f" — {e.get('referencia')}" if e.get("referencia") else ""
        texto = re.sub(r"\s+", " ", str(e.get("texto") or "")).strip()
        if len(texto) > 900:
            texto = texto[:900].rsplit(" ", 1)[0] + "..."
        linhas.append(
            f"{i}. {e.get('tipo')}: {e.get('titulo')}{ref}\n"
            f"   Pontuação de aderência: {e.get('score')}\n"
            f"   Trecho usado: {texto}"
        )
    return "\n".join(linhas)


def zel_agente_executar(atendimento=None, pergunta_livre="", fontes=None, bases=None):
    contexto = zel_agente_classificar(atendimento=atendimento, pergunta_livre=pergunta_livre)
    evidencias = zel_agente_buscar_evidencias(contexto, fontes=fontes, bases=bases)
    ok, motivo = zel_agente_checar_suficiencia(contexto, evidencias)
    resposta = zel_agente_redigir(contexto, evidencias)

    return {
        "contexto": contexto,
        "evidencias": evidencias,
        "suficiente": ok,
        "motivo": motivo,
        "resposta": resposta,
    }


def zel_resposta_util(resposta):
    texto = str(resposta or "").strip()
    if not texto:
        return False
    if texto.startswith("A Zel não encontrou fundamento validado suficiente"):
        return False
    if len(texto) < 80:
        return False
    return True


def gerar_minuta_zel_controlada(atendimento=None, pergunta_livre="", fontes=None, bases=None):
    fontes = fontes or []
    bases = bases or []

    assunto = (atendimento or {}).get("assunto") or "Não informado"
    zona = (atendimento or {}).get("zona_eleitoral") or "Não informada"
    pergunta = str(pergunta_livre or (atendimento or {}).get("descricao") or "").strip()

    if not fontes and not bases:
        return (
            "A Zel não localizou Base de Conhecimento validada nem documento de apoio validado para responder com segurança.\n\n"
            "Regra de segurança: a Zel não produz resposta sem fundamento validado."
        )

    execucao = zel_agente_executar(
        atendimento=atendimento,
        pergunta_livre=pergunta_livre,
        fontes=fontes,
        bases=bases
    )
    contexto = execucao["contexto"]
    evidencias = execucao["evidencias"]
    resposta = execucao["resposta"]

