def status_prazo_plano(prazo, status):
    if str(status or "") == "Concluído":
        return "Concluído"
    data = parse_data_opcional(prazo)
    if not data:
        return "Sem prazo"
    hoje = agora_brasilia().date()
    if data < hoje:
        return "Vencido"
    if (data - hoje).days <= 7:
        return "Vence em até 7 dias"
    return "No prazo"


