def obter_data_hora_atendimento(valor):
    """
    Converte valores de data/hora do atendimento para datetime.
    Aceita ISO, dd/mm/aaaa, dd/mm/aaaa hh:mm e valores já datetime/date.
    Retorna None quando não conseguir interpretar.
    """
    if valor is None or valor == "":
        return None

    if isinstance(valor, datetime):
        return valor

    if isinstance(valor, date):
        return datetime.combine(valor, datetime.min.time())

    texto = str(valor).strip().replace("\n", " ").replace("\r", " ")
    if not texto:
        return None

    try:
        if texto.endswith("Z"):
            texto = texto[:-1] + "+00:00"

        texto_iso = texto
        if " " in texto_iso and "T" not in texto_iso and "-" in texto_iso[:10]:
            texto_iso = texto_iso.replace(" ", "T", 1)

        dt = datetime.fromisoformat(texto_iso)
        if dt.tzinfo is not None:
            return dt.astimezone(FUSO_HORARIO_BRASILIA).replace(tzinfo=None)
        return dt
    except Exception:
        pass

    for fmt in (
        "%d/%m/%Y %H:%M",
        "%d/%m/%Y %H:%M:%S",
        "%d/%m/%Y",
        "%Y-%m-%d",
        "%d-%m-%Y",
        "%d/%m/%y",
    ):
        try:
            return datetime.strptime(texto[:19], fmt)
        except Exception:
            pass

    try:
        dt = pd.to_datetime(texto, dayfirst=True, errors="coerce")
        if pd.isna(dt):
            return None
        return dt.to_pydatetime()
    except Exception:
        return None


def dias_desde_data_hora(valor):
    dt = obter_data_hora_atendimento(valor)
    if not dt:
        return 0

    try:
        agora = agora_brasilia()
        if getattr(dt, "tzinfo", None) is None:
            dt_ref = dt.replace(tzinfo=FUSO_HORARIO_BRASILIA)
        else:
            dt_ref = dt.astimezone(FUSO_HORARIO_BRASILIA)
        return max(0, (agora - dt_ref).days)
    except Exception:
        try:
            return max(0, (datetime.now() - dt.replace(tzinfo=None)).days)
        except Exception:
            return 0


def horas_entre_datas(inicio_valor, fim_valor):
    inicio = obter_data_hora_atendimento(inicio_valor)
    fim = obter_data_hora_atendimento(fim_valor)
    if not inicio or not fim:
        return None
    horas = (fim - inicio).total_seconds() / 3600
    return horas if horas >= 0 else None


def atendimento_sem_responsavel(a):
    servidor = str(a.get("servidor") or "").strip()
    return servidor in ("", "Não informado", "Aguardando triagem")


def atendimento_sem_zona(a):
    zona = str(a.get("zona_eleitoral") or "").strip()
    return zona in ("", "Não informado")


def atendimento_sem_assunto(a):
    assunto = str(a.get("assunto") or "").strip()
    return assunto in ("", "Não informado")


def atendimento_sem_fonte(a):
    fonte = str(a.get("fonte") or "").strip()
    return fonte in ("", "Não informado")


def atendimento_aberto(a):
    return a.get("status") != STATUS_REALIZADO


def idade_atendimento_dias(a):
    return dias_desde_data_hora(a.get("criado_em"))


def dias_em_triagem(a):
    if a.get("status") == STATUS_CADASTRADO:
        return dias_desde_data_hora(a.get("criado_em"))
    horas = horas_entre_datas(a.get("criado_em"), a.get("triado_em") or a.get("atualizado_em"))
    return int(horas // 24) if horas is not None else None


def dias_em_atendimento(a):
    if a.get("status") == STATUS_EM_ATENDIMENTO:
        return dias_desde_data_hora(a.get("triado_em") or a.get("atualizado_em") or a.get("criado_em"))
    if a.get("status") == STATUS_REALIZADO:
        horas = horas_entre_datas(
            a.get("triado_em") or a.get("criado_em"),
            a.get("realizado_em") or a.get("data_realizacao") or a.get("atualizado_em")
        )
        return int(horas // 24) if horas is not None else None
    return None


def classificar_alerta_gerencial(a):
    if not atendimento_aberto(a):
        return ""

    status = a.get("status")
    prioridade = str(a.get("prioridade") or "").strip().casefold()

    if prazo_vencido(a):
        return "Prazo vencido"

    if prioridade == "urgente":
        return "Urgente em aberto"

    if status == STATUS_CADASTRADO:
        dias = dias_em_triagem(a)
        if dias is not None and dias > 2:
            return "Triagem acima de 2 dias"

    if status == STATUS_EM_ATENDIMENTO:
        dias = dias_em_atendimento(a)
        if dias is not None and dias > 5:
            return "Em atendimento acima de 5 dias"

    if atendimento_sem_responsavel(a):
        return "Sem responsável"

    return ""


def dataframe_alertas_gerenciais(lista):
    linhas = []
    for a in lista:
        alerta = classificar_alerta_gerencial(a)
        if not alerta:
            continue
        linhas.append({
            "ID": a.get("id"),
            "Seção": normalizar_secao(a.get("secao")) if "SECOES_ATENDIMENTO" in globals() else "SEPRO",
            "Status": a.get("status"),
            "Alerta": alerta,
            "Prioridade": a.get("prioridade") or "Não informado",
            "Servidor(a)": a.get("servidor") or "Não informado",
            "Zona eleitoral": a.get("zona_eleitoral") or "Não informado",
            "Assunto": a.get("assunto") or "Não informado",
            "Dias em aberto": idade_atendimento_dias(a),
        })
    if not linhas:
        return pd.DataFrame(columns=["ID", "Seção", "Status", "Alerta", "Prioridade", "Servidor(a)", "Zona eleitoral", "Assunto", "Dias em aberto"])
    return pd.DataFrame(linhas).sort_values(["Alerta", "Dias em aberto"], ascending=[True, False])


def dataframe_qualidade_base(lista):
    total = len(lista)
    dados = [
        ("Sem responsável", sum(1 for a in lista if atendimento_sem_responsavel(a))),
        ("Sem zona eleitoral", sum(1 for a in lista if atendimento_sem_zona(a))),
        ("Sem assunto", sum(1 for a in lista if atendimento_sem_assunto(a))),
        ("Sem fonte", sum(1 for a in lista if atendimento_sem_fonte(a))),
        ("Urgentes em aberto", sum(1 for a in lista if atendimento_aberto(a) and str(a.get("prioridade") or "").casefold() == "urgente")),
        ("Prazo vencido", sum(1 for a in lista if prazo_vencido(a))),
        ("Triagem acima de 2 dias", sum(1 for a in lista if a.get("status") == STATUS_CADASTRADO and (dias_em_triagem(a) or 0) > 2)),
        ("Em atendimento acima de 5 dias", sum(1 for a in lista if a.get("status") == STATUS_EM_ATENDIMENTO and (dias_em_atendimento(a) or 0) > 5)),
    ]

    linhas = []
    for item, qtd in dados:
        percentual = (qtd / total * 100) if total else 0
        linhas.append({
            "Indicador": item,
            "Qtd.": numero_br(qtd),
            "% da base": percentual_br(percentual),
        })

    return pd.DataFrame(linhas)


def dataframe_resumo_por_secao(lista):
    linhas = []
    secoes = secoes_atendimento()

    for secao in secoes:
        base = [a for a in lista if normalizar_secao(a.get("secao")) == secao]
        total = len(base)
        realizados = sum(1 for a in base if a.get("status") == STATUS_REALIZADO)
        pendentes = total - realizados
        alertas = len(dataframe_alertas_gerenciais(base))
        tempo_df = dataframe_tempo_medio_por_fonte(base)
        linhas.append({
            "Seção": secao,
            "Total": numero_br(total),
            "Pendentes": numero_br(pendentes),
            "Realizados": numero_br(realizados),
            "% realizado": percentual_br((realizados / total * 100) if total else 0),
            "Alertas": numero_br(alertas),
        })

    return pd.DataFrame(linhas)


def aplicar_filtro_gerencial(lista, filtro):
    if not filtro or filtro == "Todos":
        return lista

    resultado = []
    for a in lista:
        if filtro == "Somente alertas gerenciais" and classificar_alerta_gerencial(a):
            resultado.append(a)
        elif filtro == "Sem responsável" and atendimento_sem_responsavel(a):
            resultado.append(a)
        elif filtro == "Sem zona eleitoral" and atendimento_sem_zona(a):
            resultado.append(a)
        elif filtro == "Sem assunto" and atendimento_sem_assunto(a):
            resultado.append(a)
        elif filtro == "Sem fonte" and atendimento_sem_fonte(a):
            resultado.append(a)
        elif filtro == "Urgentes em aberto" and atendimento_aberto(a) and str(a.get("prioridade") or "").casefold() == "urgente":
            resultado.append(a)
        elif filtro == "Triagem acima de 2 dias" and a.get("status") == STATUS_CADASTRADO and (dias_em_triagem(a) or 0) > 2:
            resultado.append(a)
        elif filtro == "Em atendimento acima de 5 dias" and a.get("status") == STATUS_EM_ATENDIMENTO and (dias_em_atendimento(a) or 0) > 5:
            resultado.append(a)

    return resultado


def dataframe_evolucao_mensal_por_secao(lista):
    df = atendimentos_df(lista)
    if df.empty or "Data" not in df.columns:
        return pd.DataFrame(columns=["Mês", "Seção", "Total"])

    temp = df.copy()
    temp["Data_dt"] = pd.to_datetime(temp["Data"], dayfirst=True, errors="coerce")
    temp = temp.dropna(subset=["Data_dt"])
    if temp.empty:
        return pd.DataFrame(columns=["Mês", "Seção", "Total"])

    if "Seção" not in temp.columns:
        temp["Seção"] = "SEPRO"

    temp["Mês"] = temp["Data_dt"].dt.strftime("%m/%Y")
    resumo = temp.groupby(["Mês", "Seção"]).size().reset_index(name="Total")
    return resumo.sort_values(["Mês", "Seção"], ascending=[False, True])





def normalizar_nome_gerencial(valor):
    """Normaliza nomes para consolidar rankings sem duplicidades por caixa/acentuação básica."""
    txt = str(valor or "").strip()
    if not txt:
        return "Não informado"

    txt = " ".join(txt.split())
    # Normaliza caixa preservando conectores comuns.
    partes_minusculas = {"da", "de", "do", "das", "dos", "e"}
    partes = []
    for p in txt.lower().split():
        if p in partes_minusculas:
            partes.append(p)
        else:
            partes.append(p[:1].upper() + p[1:])
    return " ".join(partes)


def normalizar_assunto_gerencial(valor):
    txt = str(valor or "").strip()
    if not txt:
        return "Não informado"
    return " ".join(txt.split())


def dataframe_top_servidores_normalizado(lista, limite=10):
    df = atendimentos_df(lista)
    if df.empty:
        return pd.DataFrame(columns=["Servidor(a)", "Qtd."])

    col = "Servidor(a)" if "Servidor(a)" in df.columns else None
    if not col:
        return pd.DataFrame(columns=["Servidor(a)", "Qtd."])

    temp = df.copy()
    temp["Servidor(a)"] = temp[col].apply(normalizar_nome_gerencial)
    resumo = temp["Servidor(a)"].value_counts().head(limite).reset_index()
    resumo.columns = ["Servidor(a)", "Qtd."]
    return resumo


def dataframe_top_assuntos_gerencial(lista, limite=10):
    df = atendimentos_df(lista)
    if df.empty or "Assunto" not in df.columns:
        return pd.DataFrame(columns=["Assunto", "Qtd."])

    temp = df.copy()
    temp["Assunto"] = temp["Assunto"].apply(normalizar_assunto_gerencial)
    resumo = temp["Assunto"].value_counts().head(limite).reset_index()
    resumo.columns = ["Assunto", "Qtd."]
    return resumo


def dataframe_top_zonas_gerencial(lista, limite=10):
    df = atendimentos_df(lista)
    if df.empty or "Zona eleitoral" not in df.columns:
        return pd.DataFrame(columns=["Zona eleitoral", "Qtd."])

    temp = df.copy()
    temp["Zona eleitoral"] = temp["Zona eleitoral"].fillna("Não informado").replace("", "Não informado")
    resumo = temp["Zona eleitoral"].value_counts().head(limite).reset_index()
    resumo.columns = ["Zona eleitoral", "Qtd."]
    return resumo


def dataframe_prazos_gerencial(lista):
    total = len(lista or [])
    vencidos = len([a for a in (lista or []) if prazo_vencido(a)])
    urgentes = len([
        a for a in (lista or [])
        if atendimento_aberto(a) and str(a.get("prioridade") or "").casefold() == "urgente"
    ])
    sem_responsavel = len([
        a for a in (lista or [])
        if atendimento_aberto(a) and not str(a.get("servidor") or "").strip()
    ])
    pendentes_validacao = len([
        a for a in (lista or [])
        if str(a.get("situacao_validacao") or "") == "Pendente de validação"
    ])

    return pd.DataFrame([
        {"Indicador": "Total de registros", "Qtd.": total},
        {"Indicador": "Prazos vencidos", "Qtd.": vencidos},
        {"Indicador": "Urgentes abertas", "Qtd.": urgentes},
        {"Indicador": "Sem responsável", "Qtd.": sem_responsavel},
        {"Indicador": "Validação pendente", "Qtd.": pendentes_validacao},
    ])


def gerar_leitura_executiva(lista):
    total = len(lista or [])
    if total == 0:
        return "Não há registros suficientes para leitura executiva."

    realizados = len([a for a in lista if a.get("status") == STATUS_REALIZADO])
    pendentes = total - realizados
    taxa = (realizados / total * 100) if total else 0

    top_ass = dataframe_top_assuntos_gerencial(lista, 1)
    assunto = top_ass.iloc[0]["Assunto"] if not top_ass.empty else "não identificado"

    top_srv = dataframe_top_servidores_normalizado(lista, 1)
    servidor = top_srv.iloc[0]["Servidor(a)"] if not top_srv.empty else "não identificado"

    vencidos = len([a for a in lista if prazo_vencido(a)])
    urgentes = len([
        a for a in lista
        if atendimento_aberto(a) and str(a.get("prioridade") or "").casefold() == "urgente"
    ])

    partes = []
    partes.append(
        f"O acervo analisado possui {numero_br(total)} registros, com {numero_br(realizados)} realizados "
        f"e {numero_br(pendentes)} pendentes. A taxa de realização está em {taxa:.2f}%."
    )

    partes.append(
        f"O assunto mais recorrente é '{assunto}', e o maior volume de registros está associado a {servidor}."
    )

    if vencidos or urgentes:
        partes.append(
            f"Atenção gerencial: há {numero_br(vencidos)} prazo(s) vencido(s) e {numero_br(urgentes)} demanda(s) urgente(s) aberta(s)."
        )
    else:
        partes.append("Não há alertas críticos de prazo vencido ou demandas urgentes abertas no recorte atual.")

    return " ".join(partes)


