def dataframe_para_tabela_br(df):
    if df is None or df.empty:
        return df
    out = df.copy()
    for col in out.columns:
        if pd.api.types.is_numeric_dtype(out[col]):
            out[col] = out[col].map(numero_br)
    return out


def filtros_base(lista):
    lista = filtrar_lista_por_perfil(lista)
    df = atendimentos_df(lista)

    st.sidebar.subheader("Filtros")

    busca = st.sidebar.text_input("Busca livre")
    status = st.sidebar.multiselect("Status", STATUS_OPCOES)
    filtro_secoes = st.sidebar.multiselect("Seção", secoes_atendimento())
    fontes = st.sidebar.multiselect("Fonte", FONTES)
    lista_assuntos = assuntos()
    filtro_assuntos = st.sidebar.multiselect("Assunto", lista_assuntos)

    servidores = sorted(df["Servidor(a)"].dropna().astype(str).unique()) if not df.empty else []
    filtro_servidores = st.sidebar.multiselect("Servidor(a)", servidores)

    st.sidebar.markdown("**Período do atendimento**")
    data_de = st.sidebar.date_input(
        "De",
        value=None,
        format="DD/MM/YYYY",
        key="filtro_data_de"
    )
    data_ate = st.sidebar.date_input(
        "Até",
        value=None,
        format="DD/MM/YYYY",
        key="filtro_data_ate"
    )

    if df.empty:
        return []

    ids_validos = set(df["ID"].tolist())

    if busca:
        termo = busca.lower()
        df = df[
            df.astype(str).apply(
                lambda linha: linha.str.lower().str.contains(termo, na=False).any(),
                axis=1
            )
        ]

    if status:
        df = df[df["Status"].isin(status)]

    if filtro_secoes and "Seção" in df.columns:
        df = df[df["Seção"].isin(filtro_secoes)]

    if fontes:
        df = df[df["Fonte"].isin(fontes)]

    if filtro_assuntos:
        df = df[df["Assunto"].isin(filtro_assuntos)]

    if filtro_servidores:
        df = df[df["Servidor(a)"].isin(filtro_servidores)]

    if data_de or data_ate:
        datas = pd.to_datetime(df["Data"], dayfirst=True, errors="coerce")

        if data_de:
            data_de_ts = pd.Timestamp(data_de)
            df = df[datas >= data_de_ts]
            datas = pd.to_datetime(df["Data"], dayfirst=True, errors="coerce")

        if data_ate:
            data_ate_ts = pd.Timestamp(data_ate)
            df = df[datas <= data_ate_ts]

    ids_filtrados = set(df["ID"].tolist()) & ids_validos

    return [a for a in lista if a.get("id") in ids_filtrados]


