def grafico_barra_pdf(df, coluna, titulo, limite=10):
    if not MATPLOTLIB_DISPONIVEL:
        return None
    if df.empty or coluna not in df.columns:
        return None

    serie = (
        df[coluna]
        .fillna("Não informado")
        .replace("", "Não informado")
        .value_counts()
        .head(limite)
    )

    if serie.empty:
        return None

    fig, ax = plt.subplots(figsize=(7.5, 3.2))
    serie.sort_values().plot(kind="barh", ax=ax)
    ax.set_title(titulo)
    ax.set_xlabel("Quantidade")
    ax.set_ylabel("")
    ax.grid(axis="x", alpha=0.25)
    fig.tight_layout()

    buffer = BytesIO()
    fig.savefig(buffer, format="png", dpi=160, bbox_inches="tight")
    plt.close(fig)
    buffer.seek(0)
    return buffer


def grafico_linha_pdf(df, titulo="Evolução mensal"):
    if not MATPLOTLIB_DISPONIVEL:
        return None
    if df.empty or "Data" not in df.columns:
        return None

    temp = df.copy()
    temp["Data_dt"] = pd.to_datetime(temp["Data"], dayfirst=True, errors="coerce")
    temp = temp.dropna(subset=["Data_dt"])

    if temp.empty:
        return None

    serie = temp.groupby(temp["Data_dt"].dt.to_period("M")).size()
    serie.index = serie.index.astype(str)

    if serie.empty:
        return None

    fig, ax = plt.subplots(figsize=(7.5, 3.2))
    serie.plot(kind="line", marker="o", ax=ax)
    ax.set_title(titulo)
    ax.set_xlabel("Mês")
    ax.set_ylabel("Quantidade")
    ax.grid(alpha=0.25)
    fig.autofmt_xdate(rotation=35)
    fig.tight_layout()

    buffer = BytesIO()
    fig.savefig(buffer, format="png", dpi=160, bbox_inches="tight")
    plt.close(fig)
    buffer.seek(0)
    return buffer


def texto_filtros_relatorio(filtros):
    partes = []
    for chave, valor in filtros.items():
        if valor:
            if isinstance(valor, (list, tuple)):
                valor_txt = ", ".join([str(v) for v in valor]) if valor else "Todos"
            else:
                valor_txt = str(valor)
            partes.append(f"<b>{chave}:</b> {valor_txt}")
    return " | ".join(partes) if partes else "Sem filtros específicos aplicados."


def cabecalho_relatorio(canvas_obj, doc):
    canvas_obj.saveState()

    largura, altura = landscape(A4)
    margem = 1.1 * cm

    try:
        logo_bytes = BytesIO(base64.b64decode(LOGO_CORREGEDORIA_BASE64))
        canvas_obj.drawImage(
            ImageReader(logo_bytes),
            margem,
            altura - 2.25 * cm,
            width=6.8 * cm,
            height=1.35 * cm,
            preserveAspectRatio=True,
            mask="auto"
        )
    except Exception:
        canvas_obj.setFont("Helvetica-Bold", 10)
        canvas_obj.drawString(margem, altura - 1.6 * cm, "CORREGEDORIA REGIONAL ELEITORAL DA BAHIA")

    canvas_obj.setFont("Helvetica-Bold", 12)
    canvas_obj.setFillColor(colors.HexColor("#174A7C"))
    canvas_obj.drawRightString(largura - margem, altura - 1.35 * cm, "SIGA-COR")

    canvas_obj.setFont("Helvetica", 8)
    canvas_obj.setFillColor(colors.HexColor("#475569"))
    canvas_obj.drawRightString(largura - margem, altura - 1.75 * cm, "Sistema Integrado de Gestão de Atendimentos da Corregedoria")

    canvas_obj.setStrokeColor(colors.HexColor("#D9E2EF"))
    canvas_obj.line(margem, altura - 2.55 * cm, largura - margem, altura - 2.55 * cm)

    canvas_obj.setFont("Helvetica", 8)
    canvas_obj.setFillColor(colors.HexColor("#64748B"))
    canvas_obj.drawString(margem, 0.75 * cm, f"Emitido em {agora_texto_brasilia()} - Horário oficial de Brasília")
    canvas_obj.drawRightString(largura - margem, 0.75 * cm, f"Página {doc.page}")

    canvas_obj.restoreState()


def tabela_resumo_pdf(df):
    total = len(df)
    triagem = int((df["Status"] == STATUS_CADASTRADO).sum()) if not df.empty and "Status" in df.columns else 0
    em_atendimento = int((df["Status"] == STATUS_EM_ATENDIMENTO).sum()) if not df.empty and "Status" in df.columns else 0
    realizado = int((df["Status"] == STATUS_REALIZADO).sum()) if not df.empty and "Status" in df.columns else 0
    percentual = (realizado / total * 100) if total else 0

    dados = [
        ["Indicador", "Resultado"],
        ["Total de atendimentos", numero_br(total)],
        ["Em triagem", numero_br(triagem)],
        ["Em atendimento", numero_br(em_atendimento)],
        ["Atendimentos realizados", numero_br(realizado)],
        ["Percentual realizado", percentual_br(percentual)],
    ]

    tabela = Table(dados, colWidths=[7 * cm, 4 * cm])
    tabela.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#174A7C")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTNAME", (0, 1), (0, -1), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 8.5),
        ("GRID", (0, 0), (-1, -1), 0.25, colors.HexColor("#D9E2EF")),
        ("BACKGROUND", (0, 1), (-1, -1), colors.HexColor("#F8FAFC")),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.HexColor("#F8FAFC"), colors.white]),
        ("LEFTPADDING", (0, 0), (-1, -1), 6),
        ("RIGHTPADDING", (0, 0), (-1, -1), 6),
    ]))
    return tabela


def tabela_dados_pdf(df, limite=80):
    colunas_preferidas = [
        "ID", "Data", "Seção", "Zona eleitoral", "Assunto", "Servidor(a)",
        "Fonte", "Status", "Prioridade", "Origem", "Tempo de atendimento"
    ]

    colunas = [c for c in colunas_preferidas if c in df.columns]
    temp = df[colunas].head(limite).copy() if not df.empty and colunas else pd.DataFrame()

    if temp.empty:
        return Paragraph("Não há registros para compor a tabela analítica.", ParagraphStyle("normal", fontSize=9))

    dados = [colunas] + temp.fillna("").astype(str).values.tolist()

    larguras = {
        "ID": 1.2 * cm,
        "Data": 2.0 * cm,
        "Seção": 1.7 * cm,
        "Zona eleitoral": 3.5 * cm,
        "Assunto": 4.2 * cm,
        "Servidor(a)": 3.8 * cm,
        "Fonte": 2.2 * cm,
        "Status": 3.0 * cm,
        "Prioridade": 2.0 * cm,
        "Origem": 3.2 * cm,
        "Tempo de atendimento": 2.6 * cm,
    }

    tabela = Table(dados, colWidths=[larguras.get(c, 3 * cm) for c in colunas], repeatRows=1)
    tabela.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#174A7C")),
        ("TEXTCOLOR", (0, 0), (-1, 0), colors.white),
        ("FONTNAME", (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE", (0, 0), (-1, -1), 6.5),
        ("GRID", (0, 0), (-1, -1), 0.2, colors.HexColor("#D9E2EF")),
        ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#F8FAFC")]),
        ("VALIGN", (0, 0), (-1, -1), "TOP"),
        ("LEFTPADDING", (0, 0), (-1, -1), 3),
        ("RIGHTPADDING", (0, 0), (-1, -1), 3),
    ]))
    return tabela


def gerar_relatorio_pdf_sepro(df, filtros_aplicados):
    buffer_pdf = BytesIO()

    doc = SimpleDocTemplate(
        buffer_pdf,
        pagesize=landscape(A4),
        rightMargin=1.1 * cm,
        leftMargin=1.1 * cm,
        topMargin=3.0 * cm,
        bottomMargin=1.4 * cm,
        title="Relatório de Atendimentos - SIGA-COR",
    )

    estilos = getSampleStyleSheet()
    titulo = ParagraphStyle(
        "TituloSEPRO",
        parent=estilos["Title"],
        fontName="Helvetica-Bold",
        fontSize=16,
        leading=20,
        alignment=TA_CENTER,
        textColor=colors.HexColor("#174A7C"),
        spaceAfter=8,
    )
    subtitulo = ParagraphStyle(
        "SubtituloSEPRO",
        parent=estilos["Normal"],
        fontName="Helvetica",
        fontSize=9,
        leading=12,
        alignment=TA_CENTER,
        textColor=colors.HexColor("#475569"),
        spaceAfter=14,
    )
    h2 = ParagraphStyle(
        "H2SEPRO",
        parent=estilos["Heading2"],
        fontName="Helvetica-Bold",
        fontSize=11,
        leading=14,
        textColor=colors.HexColor("#174A7C"),
        spaceBefore=10,
        spaceAfter=6,
    )
    normal = ParagraphStyle(
        "NormalSEPRO",
        parent=estilos["Normal"],
        fontName="Helvetica",
        fontSize=8.5,
        leading=11,
        textColor=colors.HexColor("#1F2937"),
    )

    elementos = []

    elementos.append(Paragraph("RELATÓRIO GERENCIAL DE ATENDIMENTOS - SIGA-COR", titulo))
    elementos.append(Paragraph("SEPRO / COAJUC - SIGA-COR", subtitulo))

    elementos.append(Paragraph("1. Identificação e filtros aplicados", h2))
    elementos.append(Paragraph(f"<b>Usuário emissor:</b> {usuario_logado().get('nome', '')} ({usuario_logado().get('email', '')})", normal))
    elementos.append(Paragraph(f"<b>Data e hora de emissão:</b> {agora_texto_brasilia()} - Horário oficial de Brasília", normal))
    elementos.append(Paragraph(texto_filtros_relatorio(filtros_aplicados), normal))
    elementos.append(Spacer(1, 0.25 * cm))

    elementos.append(Paragraph("2. Resumo executivo", h2))
    elementos.append(tabela_resumo_pdf(df))
    elementos.append(Spacer(1, 0.3 * cm))

    elementos.append(Paragraph("3. Indicadores estatísticos", h2))

    graficos = [
        grafico_barra_pdf(df, "Status", "Atendimentos por status", limite=6),
        grafico_barra_pdf(df, "Assunto", "Atendimentos por assunto", limite=8),
        grafico_barra_pdf(df, "Zona eleitoral", "Zonas eleitorais que mais demandam", limite=8),
        grafico_barra_pdf(df, "Servidor(a)", "Atendimentos por servidor(a)", limite=8),
        grafico_linha_pdf(df, "Evolução mensal dos atendimentos"),
    ]

    imagens = []
    for grafico in graficos:
        if grafico:
            imagens.append(Image(grafico, width=11.5 * cm, height=5.0 * cm))

    if imagens:
        pares = []
        for i in range(0, len(imagens), 2):
            linha = imagens[i:i+2]
            if len(linha) == 1:
                linha.append("")
            pares.append(linha)
        tabela_graficos = Table(pares, colWidths=[12.0 * cm, 12.0 * cm])
        tabela_graficos.setStyle(TableStyle([
            ("VALIGN", (0, 0), (-1, -1), "TOP"),
            ("LEFTPADDING", (0, 0), (-1, -1), 2),
            ("RIGHTPADDING", (0, 0), (-1, -1), 2),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 8),
        ]))
        elementos.append(tabela_graficos)
    else:
        elementos.append(Paragraph("Não há dados suficientes para geração de gráficos estatísticos.", normal))

    elementos.append(PageBreak())

    elementos.append(Paragraph("4. Tabela analítica dos atendimentos filtrados", h2))
    elementos.append(Paragraph("A tabela abaixo apresenta os registros conforme os filtros aplicados. Para preservar a legibilidade do PDF, são exibidos até 80 registros.", normal))
    elementos.append(Spacer(1, 0.2 * cm))
    elementos.append(tabela_dados_pdf(df, limite=80))

    doc.build(elementos, onFirstPage=cabecalho_relatorio, onLaterPages=cabecalho_relatorio)

    buffer_pdf.seek(0)
    return buffer_pdf.getvalue()


def tela_relatorios_exportacao():
    st.subheader("Relatórios e exportação")

    lista = filtros_base(atendimentos())

    st.markdown("#### Filtros do relatório")

    col_data1, col_data2, col_data3 = st.columns(3)

    with col_data1:
        data_inicio_relatorio = st.date_input(
            "Data inicial",
            value=None,
            format="DD/MM/YYYY",
            key="relatorio_data_inicio"
        )

    with col_data2:
        data_fim_relatorio = st.date_input(
            "Data final",
            value=None,
            format="DD/MM/YYYY",
            key="relatorio_data_fim"
        )

    with col_data3:
        campo_data_relatorio = st.selectbox(
            "Campo de data",
            [
                "Data do atendimento",
                "Data de realização",
            ],
            key="relatorio_campo_data"
        )

    campo_data_lista = "data_realizacao" if campo_data_relatorio == "Data de realização" else "data"
    lista = filtrar_lista_por_intervalo_datas(
        lista,
        data_inicio_relatorio,
        data_fim_relatorio,
        campo=campo_data_lista
    )

    servidores_disponiveis = sorted(
        set(
            str(a.get("servidor") or "Não informado").strip()
            for a in lista
            if str(a.get("servidor") or "").strip()
        ),
        key=lambda x: x.casefold()
    )

    filtro_atendente_relatorio = st.multiselect(
        "Atendente / servidor responsável",
        servidores_disponiveis,
        key="filtro_atendente_relatorio"
    )

    if filtro_atendente_relatorio:
        lista = [
            a for a in lista
            if str(a.get("servidor") or "Não informado").strip() in filtro_atendente_relatorio
        ]

    filtro_gerencial_relatorio = st.selectbox(
        "Filtro gerencial",
        [
            "Todos",
            "Somente alertas gerenciais",
            "Sem responsável",
            "Sem zona eleitoral",
            "Sem assunto",
            "Sem fonte",
            "Urgentes em aberto",
            "Triagem acima de 2 dias",
            "Em atendimento acima de 5 dias",
        ],
        key="filtro_gerencial_relatorio"
    )
    lista = aplicar_filtro_gerencial(lista, filtro_gerencial_relatorio)

    filtro_secao_relatorio = st.multiselect("Seção", secoes_atendimento(), key="filtro_secao_relatorio")
    if filtro_secao_relatorio:
        lista = [a for a in lista if normalizar_secao(a.get("secao")) in filtro_secao_relatorio]

    filtro_tempo_atendimento_relatorio = st.selectbox(
        "Tempo de atendimento",
        [
            "Todos",
            "Até 24 horas",
            "De 1 a 3 dias",
            "De 3 a 7 dias",
            "Acima de 7 dias",
            "Sem tempo calculado",
        ],
        key="filtro_tempo_atendimento_relatorio"
    )

    lista = aplicar_filtro_tempo_atendimento(lista, filtro_tempo_atendimento_relatorio)

    df = atendimentos_df(lista)

    zonas_relatorio = sorted(df["Zona eleitoral"].dropna().astype(str).unique()) if not df.empty and "Zona eleitoral" in df.columns else []
    filtro_zona_relatorio = st.multiselect("Zona Eleitoral", zonas_relatorio)

    if filtro_zona_relatorio:
        df = df[df["Zona eleitoral"].isin(filtro_zona_relatorio)]
        lista = [a for a in lista if a.get("zona_eleitoral") in filtro_zona_relatorio]

    if not df.empty:
        mapa_horas = {}
        for atendimento in lista:
            mapa_horas[str(atendimento.get("id"))] = formatar_tempo_horas(calcular_horas_entre_triagem_realizacao(atendimento))
        if "ID" in df.columns:
            df["Tempo de atendimento"] = df["ID"].astype(str).map(mapa_horas).fillna("Não calculado")

    if df.empty:
        st.info("Nenhum registro para exportar.")
        return

    st.markdown("#### Base filtrada")
    st.dataframe(df, use_container_width=True, hide_index=True)

    periodo_texto = ""
    if data_inicio_relatorio or data_fim_relatorio:
        inicio_txt = data_inicio_relatorio.strftime("%d/%m/%Y") if data_inicio_relatorio else "início"
        fim_txt = data_fim_relatorio.strftime("%d/%m/%Y") if data_fim_relatorio else "fim"
        periodo_texto = f"{inicio_txt} a {fim_txt} ({campo_data_relatorio})"

    filtros_para_pdf = {
        "Quantidade de registros": numero_br(len(df)),
        "Período": periodo_texto,
        "Atendente/servidor": filtro_atendente_relatorio if filtro_atendente_relatorio else [],
        "Filtro gerencial": filtro_gerencial_relatorio if "filtro_gerencial_relatorio" in locals() else "Todos",
        "Seção": filtro_secao_relatorio if "filtro_secao_relatorio" in locals() else [],
        "Zona Eleitoral": filtro_zona_relatorio if "filtro_zona_relatorio" in locals() else [],
        "Data de emissão": agora_texto_brasilia(),
    }

    if not MATPLOTLIB_DISPONIVEL:
        st.warning("Biblioteca matplotlib não instalada no ambiente. O relatório PDF será gerado sem gráficos estatísticos.")

    st.markdown("#### Relatório apresentável")
    st.caption("Gera relatório em PDF com timbre, resumo gerencial, gráficos estatísticos e tabela analítica conforme a base filtrada.")

    pdf_relatorio = gerar_relatorio_pdf_sepro(df, filtros_para_pdf)

    st.download_button(
        "Gerar relatório PDF apresentável",
        data=pdf_relatorio,
        file_name=f"relatorio_siga_cor_atendimentos_{agora_brasilia().strftime('%Y%m%d_%H%M')}.pdf",
        mime="application/pdf",
        type="primary"
    )

    st.divider()

    st.markdown("#### Relatórios gerenciais")
    st.dataframe(dataframe_qualidade_base(lista), use_container_width=True, hide_index=True)
    st.dataframe(dataframe_alertas_gerenciais(lista), use_container_width=True, hide_index=True)

    st.divider()

    col1, col2 = st.columns(2)

    with col1:
        st.markdown("#### Relatório por status")
        st.dataframe(df["Status"].value_counts().rename_axis("Status").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

        st.markdown("#### Relatório por atendente/servidor")
        st.dataframe(df["Servidor(a)"].value_counts().rename_axis("Servidor(a)").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

    with col2:
        st.markdown("#### Relatório por assunto")
        st.dataframe(df["Assunto"].value_counts().rename_axis("Assunto").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

        st.markdown("#### Relatório por fonte")
        st.dataframe(df["Fonte"].value_counts().rename_axis("Fonte").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

        if "Complexidade" in df.columns:
            st.markdown("#### Relatório por complexidade")
            st.dataframe(df["Complexidade"].value_counts().rename_axis("Complexidade").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

        if "Seção" in df.columns:
            st.markdown("#### Relatório por seção")
            st.dataframe(df["Seção"].value_counts().rename_axis("Seção").reset_index(name="Quantidade"), use_container_width=True, hide_index=True)

    st.divider()

    buffer = BytesIO()
    with pd.ExcelWriter(buffer, engine="openpyxl") as writer:
        df.to_excel(writer, index=False, sheet_name="Atendimentos")
        df["Status"].value_counts().rename_axis("Status").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por status")
        df["Servidor(a)"].value_counts().rename_axis("Servidor(a)").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por servidor")
        df["Assunto"].value_counts().rename_axis("Assunto").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por assunto")
        df["Fonte"].value_counts().rename_axis("Fonte").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por fonte")
        dataframe_qualidade_base(lista).to_excel(writer, index=False, sheet_name="Qualidade base")
        dataframe_alertas_gerenciais(lista).to_excel(writer, index=False, sheet_name="Alertas gerenciais")
        if "Complexidade" in df.columns:
            df["Complexidade"].value_counts().rename_axis("Complexidade").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por complexidade")
        if "Seção" in df.columns:
            df["Seção"].value_counts().rename_axis("Seção").reset_index(name="Quantidade").to_excel(writer, index=False, sheet_name="Por seção")

    st.download_button(
        "Baixar relatório em Excel",
        data=buffer.getvalue(),
        file_name=f"relatorio_atendimentos_siga_cor_{agora_brasilia().strftime('%Y%m%d_%H%M')}.xlsx",
        mime="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )

    csv = df.to_csv(index=False, sep=";").encode("utf-8-sig")
    st.download_button(
        "Baixar base em CSV",
        data=csv,
        file_name=f"base_atendimentos_siga_cor_{agora_brasilia().strftime('%Y%m%d_%H%M')}.csv",
        mime="text/csv"
    )



def tela_assuntos():
    st.subheader("Assuntos")
    st.caption("Área exclusiva do administrador. Os assuntos agora são organizados por tipologia, que funciona como gênero/classificação superior.")

    if not eh_admin():
        st.warning("Apenas administradores podem gerenciar assuntos.")
        return

    registros = assunto_rows()

    st.markdown("### Incluir novo assunto")
    with st.form("form_assunto"):
        col_a, col_b, col_c = st.columns([2.2, 1.2, 1.6])
        with col_a:
            novo = st.text_input("Novo assunto")
        with col_b:
            secao_novo = st.selectbox("Seção do assunto", secoes_atendimento())
        with col_c:
            tipologia_nova = st.selectbox(
                "Tipologia",
                tipologias_assunto(),
                index=tipologias_assunto().index("Não classificado")
            )

        if st.form_submit_button("Adicionar assunto", type="primary"):
            novo = novo.strip()
            tipologia_nova = normalizar_tipologia_assunto(tipologia_nova, novo)
            if not novo:
                st.warning("Informe um assunto.")
            elif any(
                r["nome"].casefold() == novo.casefold()
                and normalizar_secao(r["secao"]) == secao_novo
                for r in registros
            ):
                st.warning("Este assunto já está cadastrado para esta seção.")
            else:
                registros.append({
                    "nome": novo,
                    "secao": secao_novo,
                    "categoria": tipologia_nova,
                    "tipologia": tipologia_nova,
                    "subcategoria": "",
                    "ordem": 0,
                    "ativo": True,
                })
                salvar_assuntos_registros(registros)
                st.success(f"Assunto adicionado à seção {secao_novo}, na tipologia {tipologia_nova}.")
                st.rerun()

    st.divider()
    st.markdown("#### Assuntos cadastrados por seção")
    st.caption("Use as abas abaixo para visualizar e editar separadamente os assuntos da SEPRO e da SEOCE.")

    abas = st.tabs(secoes_atendimento())

    for aba, secao_exibida in zip(abas, secoes_atendimento()):
        with aba:
            registros_secao = [
                r for r in registros
                if normalizar_secao(r.get("secao")) == secao_exibida
                and str(r.get("nome", "")).strip() != "Não informado"
            ]

            busca = st.text_input(
                f"Buscar assunto em {secao_exibida}",
                key=f"busca_assuntos_{secao_exibida}",
                placeholder="Digite parte do assunto ou da tipologia"
            )

            if busca.strip():
                termo = busca.strip().casefold()
                registros_secao = [
                    r for r in registros_secao
                    if termo in str(r.get("nome", "")).casefold()
                    or termo in normalizar_tipologia_assunto(r.get("tipologia") or r.get("categoria"), r.get("nome")).casefold()
                ]

            st.markdown(f"### {secao_exibida}")
            st.caption(f"Total de assuntos exibidos para {secao_exibida}: {len(registros_secao)}")

            if registros_secao:
                resumo = {}
                for r in registros_secao:
                    tip = normalizar_tipologia_assunto(r.get("tipologia") or r.get("categoria"), r.get("nome"))
                    resumo[tip] = resumo.get(tip, 0) + 1
                st.caption(" | ".join([f"{k}: {v}" for k, v in sorted(resumo.items())]))

            if not registros_secao:
                st.info(f"Nenhum assunto cadastrado para {secao_exibida}.")
                continue

            for idx, registro in enumerate(registros_secao):
                assunto = registro.get("nome", "")
                secao_atual = normalizar_secao(registro.get("secao"))
                tipologia_atual = normalizar_tipologia_assunto(
                    registro.get("tipologia") or registro.get("categoria"),
                    assunto
                )

                idx_global = next(
                    (
                        i for i, r in enumerate(registros)
                        if r.get("nome") == assunto
                        and normalizar_secao(r.get("secao")) == secao_atual
                    ),
                    None
                )

                if idx_global is None:
                    continue

                with st.container(border=True):
                    col1, col2, col3, col4, col5 = st.columns([2.6, 1.15, 1.8, 0.85, 0.9])

                    with col1:
                        editado = st.text_input(
                            "Assunto",
                            value=assunto,
                            key=f"assunto_edit_{secao_exibida}_{idx_global}_{assunto}"
                        )

                    with col2:
                        nova_secao = st.selectbox(
                            "Seção",
                            secoes_atendimento(),
                            index=secoes_atendimento().index(secao_atual) if secao_atual in secoes_atendimento() else 0,
                            key=f"assunto_secao_{secao_exibida}_{idx_global}_{assunto}"
                        )

                    with col3:
                        nova_tipologia = st.selectbox(
                            "Tipologia",
                            tipologias_assunto(),
                            index=tipologias_assunto().index(tipologia_atual) if tipologia_atual in tipologias_assunto() else 0,
                            key=f"assunto_tipologia_{secao_exibida}_{idx_global}_{assunto}"
                        )

                    with col4:
                        st.write("")
                        st.write("")
                        if st.button("Salvar", key=f"assunto_salvar_{secao_exibida}_{idx_global}_{assunto}"):
                            editado = editado.strip()
                            nova_tipologia = normalizar_tipologia_assunto(nova_tipologia, editado)
                            if not editado:
                                st.warning("O assunto não pode ficar vazio.")
                            elif any(
                                i != idx_global
                                and r["nome"].casefold() == editado.casefold()
                                and normalizar_secao(r["secao"]) == nova_secao
                                for i, r in enumerate(registros)
                            ):
                                st.warning("Já existe outro assunto com este nome para esta seção.")
                            else:
                                registros[idx_global] = {
                                    **registros[idx_global],
                                    "nome": editado,
                                    "secao": nova_secao,
                                    "categoria": nova_tipologia,
                                    "tipologia": nova_tipologia,
                                    "ativo": True,
                                }
                                salvar_assuntos_registros(registros)
                                st.success("Assunto atualizado.")
                                st.rerun()

                    with col5:
                        st.write("")
                        st.write("")
                        confirmar = st.checkbox(
                            "Confirmar",
                            key=f"assunto_conf_{secao_exibida}_{idx_global}_{assunto}"
                        )
                        if st.button("Excluir", key=f"assunto_excluir_{secao_exibida}_{idx_global}_{assunto}"):
                            if not confirmar:
                                st.warning("Marque a confirmação antes de excluir.")
                            else:
                                novos = [r for i, r in enumerate(registros) if i != idx_global]
                                salvar_assuntos_registros(novos)
                                st.success("Assunto removido da lista de opções. Registros antigos foram preservados.")
                                st.rerun()




def tela_usuarios():
    st.subheader("Usuários internos")
    st.caption("Área exclusiva do administrador. Use esta tela para servidores da SEPRO, SEOCE, chefias, administradores e perfis de consulta interna.")

    if not eh_admin():
        st.warning("Apenas administradores podem gerenciar usuários.")
        return

    lista = usuarios()
    df = pd.DataFrame(lista)

    if not df.empty:
        exibir = df.copy()
        for col in ["senha_hash", "token_validacao", "token_recuperacao"]:
            if col in exibir.columns:
                exibir = exibir.drop(columns=[col])
        st.dataframe(exibir, use_container_width=True, hide_index=True)
    else:
        st.info("Nenhum usuário cadastrado.")

    st.divider()

    st.markdown("#### Editar cadastro de usuário")

    opcoes = [f"{u.get('nome')} - {u.get('email')}" for u in lista]
    if not opcoes:
        return

    selecionado = st.selectbox("Selecione o usuário", opcoes)
    email_sel = selecionado.split(" - ")[-1]

    usuario = next((u for u in lista if u.get("email") == email_sel), None)
    if not usuario:
        return

    email_original = normalizar_email(usuario.get("email"))
    email_logado = normalizar_email(usuario_logado().get("email"))

    with st.form(f"form_editar_usuario_{email_original}"):
        st.markdown("##### Dados cadastrais")

        col_dados1, col_dados2 = st.columns(2)

        with col_dados1:
            novo_nome = st.text_input(
                "Nome completo",
                value=usuario.get("nome", ""),
                key=f"usuario_nome_{email_original}"
            )

        with col_dados2:
            novo_email = normalizar_email(st.text_input(
                "E-mail institucional",
                value=usuario.get("email", ""),
                key=f"usuario_email_{email_original}"
            ))

        st.markdown("##### Perfil e acesso")

        col1, col2, col3, col4 = st.columns(4)

        with col1:
            perfis_internos = [p for p in PERFIS_USUARIO if p != "Zona Eleitoral"]
            perfil_usuario_atual = perfil_normalizado(usuario.get("perfil"))
            novo_perfil = st.selectbox(
                "Perfil",
                perfis_internos,
                index=perfis_internos.index(perfil_usuario_atual) if perfil_usuario_atual in perfis_internos else 0,
                key=f"usuario_perfil_{email_original}"
            )

        with col2:
            secao_usuario_atual = normalizar_secao(usuario.get("secao_operador"))
            nova_secao_operador = st.selectbox(
                "Operador da seção",
                secoes_atendimento(),
                index=secoes_atendimento().index(secao_usuario_atual) if secao_usuario_atual in secoes_atendimento() else 0,
                key=f"usuario_secao_{email_original}",
                disabled=(perfil_normalizado(novo_perfil) == "Zona Eleitoral")
            )

        with col3:
            ativo = st.checkbox(
                "Ativo",
                value=usuario.get("ativo", True),
                key=f"usuario_ativo_{email_original}"
            )

        with col4:
            validado = st.checkbox(
                "Validado",
                value=usuario.get("validado", False),
                key=f"usuario_validado_{email_original}"
            )

        zona_usuario_atual = usuario.get("zona_eleitoral") or zona_eleitoral_usuario_logado() if normalizar_email(usuario.get("email")) == normalizar_email((usuario_logado() or {}).get("email")) else usuario.get("zona_eleitoral", "")
        if perfil_normalizado(novo_perfil) == "Zona Eleitoral":
            st.markdown("##### Vinculação da Zona Eleitoral")
            col_z1, col_z2 = st.columns([2, 1])
            with col_z1:
                zona_usuario = st.selectbox(
                    "Zona eleitoral vinculada ao usuário",
                    opcoes_zonas_nacionais(TRIBUNAL_PADRAO),
                    index=opcoes_zonas_nacionais(TRIBUNAL_PADRAO).index(zona_usuario_atual) if zona_usuario_atual in opcoes_zonas_nacionais(TRIBUNAL_PADRAO) else 0,
                    key=f"usuario_zona_eleitoral_{email_original}"
                )
            with col_z2:
                st.caption(
                    "Para usuário de Zona Eleitoral, este vínculo define quais atendimentos ele poderá visualizar no Portal das Zonas."
                )
        else:
            zona_usuario = ""

        st.markdown("##### Senha")

        alterar_senha = st.checkbox(
            "Redefinir senha deste usuário",
            value=False,
            key=f"usuario_alt_senha_{email_original}"
        )

        nova_senha = ""
        confirmar_senha = ""

        if alterar_senha:
            col_s1, col_s2 = st.columns(2)
            with col_s1:
                nova_senha = st.text_input(
                    "Nova senha",
                    type="password",
                    key=f"usuario_nova_senha_{email_original}"
                )
            with col_s2:
                confirmar_senha = st.text_input(
                    "Confirmar nova senha",
                    type="password",
                    key=f"usuario_conf_senha_{email_original}"
                )

        salvar = st.form_submit_button("Salvar alterações do usuário", type="primary")

    if salvar:
        novo_nome = novo_nome.strip()
        novo_email = normalizar_email(novo_email)

        if not novo_nome:
            st.warning("Informe o nome do usuário.")
            return

        if not email_institucional(novo_email):
            st.warning(f"O e-mail deve terminar com {DOMINIO_INSTITUCIONAL}.")
            return

        if novo_email != email_original and any(normalizar_email(u.get("email")) == novo_email for u in lista):
            st.warning("Já existe outro usuário cadastrado com este e-mail.")
            return

        if usuario.get("email") == email_logado and not ativo:
            st.warning("Você não pode desativar o próprio usuário enquanto estiver logado.")
            return

        if usuario.get("email") == email_logado and perfil_normalizado(novo_perfil) not in ("Administrador geral", "Administrador"):
            admins_ativos = [
                u for u in lista
                if normalizar_email(u.get("email")) != email_logado
                and perfil_normalizado(u.get("perfil")) in ("Administrador geral", "Administrador")
                and u.get("ativo", True)
                and u.get("validado", False)
            ]

            if not admins_ativos:
                st.warning("Você não pode remover o próprio perfil de administrador se não houver outro administrador ativo e validado.")
                return

        if alterar_senha:
            if not nova_senha or len(nova_senha) < 6:
                st.warning("A nova senha deve ter pelo menos 6 caracteres.")
                return
            if nova_senha != confirmar_senha:
                st.warning("As senhas não conferem.")
                return

        if perfil_normalizado(novo_perfil) == "Zona Eleitoral":
            if not zona_usuario or zona_usuario == "Não informado":
                st.warning("Para usuário de Zona Eleitoral, informe a zona vinculada.")
                return
            email_zona_sugerido = email_zona_eleitoral(zona_usuario)
            if email_zona_sugerido and normalizar_email(novo_email) != normalizar_email(email_zona_sugerido):
                st.info(
                    f"Atenção: o e-mail padrão da {zona_usuario} seria {email_zona_sugerido}. "
                    "O cadastro será permitido, mas o vínculo de acesso será definido pela zona selecionada."
                )

        usuario["nome"] = novo_nome
        usuario["email"] = novo_email
        usuario["perfil"] = novo_perfil
        usuario["secao_operador"] = "" if perfil_normalizado(novo_perfil) == "Zona Eleitoral" else nova_secao_operador
        usuario["zona_eleitoral"] = zona_usuario if perfil_normalizado(novo_perfil) == "Zona Eleitoral" else ""
        usuario["ativo"] = ativo
        usuario["validado"] = validado
        usuario["atualizado_em"] = agora_iso()

        if alterar_senha:
            usuario["senha_hash"] = senha_hash(nova_senha)
            usuario["token_recuperacao"] = ""

        salvar_usuarios(lista)

        if email_original != novo_email:
            try:
                supabase_update("sessoes", {"email": novo_email, "nome": novo_nome}, "email", email_original)
            except Exception:
                pass

        if email_original == email_logado:
            st.session_state["usuario"] = usuario

        st.success("Cadastro do usuário atualizado.")
        st.rerun()

    st.divider()
    st.markdown("#### Excluir usuário")

    if usuario.get("email") == email_logado:
        st.warning("Você não pode excluir o próprio usuário enquanto estiver logado.")
    else:
        admins_ativos = [
            u for u in lista
            if perfil_normalizado(u.get("perfil")) in ("Administrador geral", "Administrador")
            and u.get("ativo", True)
            and u.get("email") != usuario.get("email")
        ]

        if perfil_normalizado(usuario.get("perfil")) in ("Administrador geral", "Administrador") and not admins_ativos:
            st.warning("Não é permitido excluir o último administrador ativo.")
        else:
            confirmar = st.checkbox(f"Confirmo a exclusão de {usuario.get('email')}")
            if st.button("Excluir usuário", type="secondary"):
                if not confirmar:
                    st.warning("Marque a confirmação antes de excluir.")
                else:
                    nova_lista = [u for u in lista if u.get("email") != usuario.get("email")]
                    salvar_usuarios(nova_lista)
                    st.success("Usuário excluído.")
                    st.rerun()






def tela_modelos_resposta():
    aviso_modo_visualizacao()
    st.subheader("Textos-padrão / Modelos de resposta")
    st.caption("Textos prontos ou semiprontos para agilizar respostas às zonas, vinculados por seção, assunto e fundamento.")

    secao_filtro = st.selectbox("Seção", ["Todas"] + secoes_atendimento(), key="modelo_secao_filtro")
    incluir_superadas = st.checkbox("Exibir orientações superadas", value=True, key="modelo_exibir_superadas")
    assunto_filtro = st.text_input("Filtrar por assunto, título ou palavra-chave", key="modelo_busca")

    rows = modelos_resposta_rows(
        None if secao_filtro == "Todas" else secao_filtro,
        incluir_superadas=incluir_superadas,
    )
    df = pd.DataFrame(rows)

    if not df.empty and assunto_filtro:
        termo = assunto_filtro.casefold()
        df = df[df.astype(str).apply(lambda linha: linha.str.casefold().str.contains(termo, na=False).any(), axis=1)]

    if not df.empty:
        df_exibir = df.copy()
        colunas_exibir = [
            "id", "secao", "assunto", "titulo", "fundamento_normativo",
            "criado_por_nome", "criado_por_email", "criado_em",
            "versao", "superada", "data_superacao", "superada_por_nome", "motivo_superacao", "modelo_substituto_id"
        ]
        colunas_exibir = [c for c in colunas_exibir if c in df_exibir.columns]
        st.dataframe(df_exibir[colunas_exibir], use_container_width=True, hide_index=True)
    else:
        st.info("Nenhum modelo cadastrado.")

    if usuario_pode_ver_memoria_avancada():
        st.divider()
        st.markdown("### Cadastrar novo modelo")

        with st.form("form_modelo_resposta"):
            col1, col2 = st.columns(2)
            with col1:
                secao = st.selectbox("Seção do modelo", secoes_atendimento(), key="modelo_novo_secao")
                lista_assuntos_secao = assuntos(secao)
                assunto = st.selectbox(
                    "Assunto vinculado",
                    lista_assuntos_secao,
                    index=0,
                    key="modelo_novo_assunto"
                )
                titulo = st.text_input("Título do modelo", key="modelo_novo_titulo")
            with col2:
                fundamento = st.text_area("Fundamento normativo", key="modelo_novo_fundamento")
                st.caption(f"Data do modelo: será registrada automaticamente em {agora_texto_brasilia()}.")
            texto_modelo = st.text_area("Texto do modelo", height=220, key="modelo_novo_texto")

            if st.form_submit_button("Salvar modelo", type="primary"):
                if not titulo.strip() or not texto_modelo.strip():
                    st.warning("Informe o título e o texto do modelo.")
                else:
                    usuario = usuario_logado() or {}
                    row = {
                        "secao": secao,
                        "assunto": assunto or "Não informado",
                        "titulo": titulo.strip(),
                        "texto_modelo": texto_modelo.strip(),
                        "fundamento_normativo": fundamento.strip(),
                        "criado_por_email": usuario.get("email", ""),
                        "criado_por_nome": usuario.get("nome", ""),
                        "ativo": True,
                        "versao": 1,
                        "superada": False,
                        "data_superacao": None,
                        "motivo_superacao": "",
                        "superada_por_email": "",
                        "superada_por_nome": "",
                        "criado_em": agora_iso(),
                        "atualizado_em": agora_iso(),
                    }
                    supabase_insert_silencioso("modelos_resposta", [row])
                    st.success("Modelo cadastrado.")
                    st.rerun()

        st.divider()
        st.markdown("### Editar, excluir ou marcar orientação como superada")

        modelos_edicao = modelos_resposta_rows(incluir_superadas=True)
        if not modelos_edicao:
            st.info("Nenhum modelo disponível para edição.")
            return

        opcoes = [
            f"{m.get('id')} - {m.get('secao')} - {m.get('assunto')} - {m.get('titulo')}"
            for m in modelos_edicao
        ]
        selecionado = st.selectbox("Selecione o modelo", opcoes, key="modelo_editar_select")
        modelo_id = int(str(selecionado).split(" - ")[0])
        modelo = next((m for m in modelos_edicao if int(m.get("id")) == modelo_id), None)

        if not modelo:
            return

        with st.form(f"form_editar_modelo_{modelo_id}"):
            col1, col2 = st.columns(2)
            with col1:
                secao_edit = st.selectbox(
                    "Seção",
                    secoes_atendimento(),
                    index=secoes_atendimento().index(normalizar_secao(modelo.get("secao"))) if normalizar_secao(modelo.get("secao")) in secoes_atendimento() else 0,
                    key=f"modelo_secao_edit_{modelo_id}"
                )
                lista_assuntos_edit = assuntos(secao_edit)
                assunto_atual = modelo.get("assunto") or "Não informado"
                if assunto_atual not in lista_assuntos_edit:
                    lista_assuntos_edit = [assunto_atual] + [a for a in lista_assuntos_edit if a != assunto_atual]
                assunto_edit = st.selectbox(
                    "Assunto vinculado",
                    lista_assuntos_edit,
                    index=lista_assuntos_edit.index(assunto_atual) if assunto_atual in lista_assuntos_edit else 0,
                    key=f"modelo_assunto_edit_{modelo_id}"
                )
                titulo_edit = st.text_input("Título", value=modelo.get("titulo", ""), key=f"modelo_titulo_edit_{modelo_id}")
            with col2:
                fundamento_edit = st.text_area("Fundamento normativo", value=modelo.get("fundamento_normativo", ""), key=f"modelo_fund_edit_{modelo_id}")
                versao_modelo_edit = st.number_input(
                    "Versão",
                    min_value=1,
                    step=1,
                    value=int(modelo.get("versao") or 1),
                    key=f"modelo_versao_edit_{modelo_id}"
                )
                st.caption(f"Data do modelo: {formatar_data_hora_brasilia(modelo.get('criado_em')) if modelo.get('criado_em') else 'Não registrada'}")
                st.caption(f"Última atualização: {formatar_data_hora_brasilia(modelo.get('atualizado_em')) if modelo.get('atualizado_em') else 'Não registrada'}")

            texto_edit = st.text_area("Texto do modelo", value=modelo.get("texto_modelo", ""), height=220, key=f"modelo_texto_edit_{modelo_id}")

            superada_edit = st.checkbox(
                "Marcar como entendimento superado",
                value=bool(modelo.get("superada", False)),
                key=f"modelo_superada_edit_{modelo_id}"
            )
            motivo_superacao = st.text_area(
                "Motivo da superação / observação para memória institucional",
                value=modelo.get("motivo_superacao", ""),
                key=f"modelo_motivo_superada_{modelo_id}"
            )

            colb1, colb2 = st.columns(2)
            with colb1:
                salvar = st.form_submit_button("Salvar alterações", type="primary")
            with colb2:
                excluir = st.form_submit_button("Excluir modelo")

        if salvar:
            usuario = usuario_logado() or {}
            dados = {
                "secao": secao_edit,
                "assunto": assunto_edit,
                "titulo": titulo_edit.strip(),
                "texto_modelo": texto_edit.strip(),
                "fundamento_normativo": fundamento_edit.strip(),
                "versao": int(versao_modelo_edit),
                "data_revisao": agora_iso(),
                "revisado_por_email": usuario.get("email", ""),
                "revisado_por_nome": usuario.get("nome", ""),
                "superada": bool(superada_edit),
                "motivo_superacao": motivo_superacao.strip(),
                "atualizado_em": agora_iso(),
            }

            if bool(superada_edit) and not modelo.get("superada", False):
                dados["data_superacao"] = agora_iso()
                dados["superada_por_email"] = usuario.get("email", "")
                dados["superada_por_nome"] = usuario.get("nome", "")
            elif not bool(superada_edit):
                dados["data_superacao"] = None
                dados["superada_por_email"] = ""
                dados["superada_por_nome"] = ""
                dados["motivo_superacao"] = ""

            supabase_update_silencioso("modelos_resposta", dados, "id", modelo_id)
            st.success("Modelo atualizado.")
            st.rerun()

        if excluir:
            supabase_update_silencioso(
                "modelos_resposta",
                {
                    "ativo": False,
                    "atualizado_em": agora_iso(),
                },
                "id",
                modelo_id
            )
            st.success("Modelo excluído da lista ativa. O registro permanece preservado no banco para memória.")
            st.rerun()




def tela_usuarios_zonas():
    st.subheader("Usuários das Zonas Eleitorais")
    st.caption(
        "Cadastro específico para acesso externo das Zonas Eleitorais. "
        "Esses usuários acessam somente o Portal das Zonas, a base de conhecimento institucional "
        "e os atendimentos vinculados à própria zona."
    )

    if not eh_admin():
        st.warning("Apenas administradores podem gerenciar usuários das zonas.")
        return

    lista = usuarios()
    usuarios_zona = [
        u for u in lista
        if perfil_normalizado(u.get("perfil")) == "Zona Eleitoral"
    ]

    st.markdown("### Cadastrar usuário de Zona Eleitoral")

    with st.form("form_novo_usuario_zona"):
        col1, col2 = st.columns(2)

        with col1:
            zona = st.selectbox(
                "Zona eleitoral",
                opcoes_zonas_nacionais(TRIBUNAL_PADRAO),
                key="novo_usuario_zona_zona"
            )

            n_zona = numero_zona_eleitoral(zona)
            nome_padrao = f"{n_zona:03d}ª Zona Eleitoral" if n_zona else ""

            nome = st.text_input(
                "Nome de exibição",
                value=nome_padrao,
                key="novo_usuario_zona_nome"
            )

        with col2:
            email_padrao = email_zona_eleitoral(zona) if zona and zona != "Não informado" else ""
            email = normalizar_email(st.text_input(
                "E-mail de acesso",
                value=email_padrao,
                key="novo_usuario_zona_email"
            ))

            senha = st.text_input(
                "Senha inicial",
                type="password",
                key="novo_usuario_zona_senha"
            )

        col3, col4 = st.columns(2)
        with col3:
            ativo = st.checkbox("Ativo", value=True, key="novo_usuario_zona_ativo")
        with col4:
            validado = st.checkbox("Validado", value=True, key="novo_usuario_zona_validado")

        st.caption(
            "Sugestão: utilize o e-mail institucional da zona no padrão zonaXXX@tre-ba.jus.br. "
            "O vínculo da zona será usado para restringir a visualização dos atendimentos."
        )

        criar = st.form_submit_button("Criar usuário da Zona", type="primary")

    if criar:
        if not zona or zona == "Não informado" or not numero_zona_eleitoral(zona):
            st.warning("Informe a zona eleitoral.")
            return

        if not nome.strip():
            st.warning("Informe o nome de exibição.")
            return

        if not email_institucional(email):
            st.warning(f"O e-mail deve terminar com {DOMINIO_INSTITUCIONAL}.")
            return

        if any(normalizar_email(u.get("email")) == email for u in lista):
            st.warning("Já existe usuário cadastrado com este e-mail.")
            return

        if not senha or len(senha) < 6:
            st.warning("A senha inicial deve ter pelo menos 6 caracteres.")
            return

        novo = {
            "nome": nome.strip(),
            "email": email,
            "senha_hash": senha_hash(senha),
            "perfil": "Zona Eleitoral",
            "secao_operador": "",
            "zona_eleitoral": zona,
            "ativo": ativo,
            "validado": validado,
            "token_validacao": "",
            "token_recuperacao": "",
            "criado_em": agora_iso(),
            "atualizado_em": agora_iso(),
        }

        lista.append(novo)
        salvar_usuarios(lista)
        st.success(f"Usuário da {zona} criado com acesso restrito ao Portal das Zonas.")
        st.rerun()

    st.divider()
    st.markdown("### Usuários de Zona cadastrados")

    if not usuarios_zona:
        st.info("Nenhum usuário de Zona Eleitoral cadastrado.")
        return

    dados = []
    for u in usuarios_zona:
        dados.append({
            "Zona": u.get("zona_eleitoral") or "",
            "Nome": u.get("nome"),
            "E-mail": u.get("email"),
            "Ativo": "Sim" if u.get("ativo", True) else "Não",
            "Validado": "Sim" if u.get("validado", False) else "Não",
        })

    st.dataframe(pd.DataFrame(dados), use_container_width=True, hide_index=True)

    st.markdown("### Editar usuário de Zona")

    opcoes = [
        f"{u.get('zona_eleitoral') or 'Zona não vinculada'} - {u.get('nome')} - {u.get('email')}"
        for u in usuarios_zona
    ]

    selecionado = st.selectbox("Selecione o usuário da zona", opcoes, key="editar_usuario_zona_select")
    email_sel = selecionado.split(" - ")[-1]

    usuario = next((u for u in lista if normalizar_email(u.get("email")) == normalizar_email(email_sel)), None)
    if not usuario:
        st.warning("Usuário não encontrado.")
        return

    email_original = normalizar_email(usuario.get("email"))

    with st.form(f"form_editar_usuario_zona_{email_original}"):
        col1, col2 = st.columns(2)

        with col1:
            zona_atual = usuario.get("zona_eleitoral") or ""
            nova_zona = st.selectbox(
                "Zona eleitoral vinculada",
                opcoes_zonas_nacionais(TRIBUNAL_PADRAO),
                index=opcoes_zonas_nacionais(TRIBUNAL_PADRAO).index(zona_atual) if zona_atual in opcoes_zonas_nacionais(TRIBUNAL_PADRAO) else 0,
                key=f"editar_usuario_zona_zona_{email_original}"
            )

            novo_nome = st.text_input(
                "Nome de exibição",
                value=usuario.get("nome", ""),
                key=f"editar_usuario_zona_nome_{email_original}"
            )

        with col2:
            novo_email = normalizar_email(st.text_input(
                "E-mail de acesso",
                value=usuario.get("email", ""),
                key=f"editar_usuario_zona_email_{email_original}"
            ))

            ativo = st.checkbox(
                "Ativo",
                value=usuario.get("ativo", True),
                key=f"editar_usuario_zona_ativo_{email_original}"
            )

            validado = st.checkbox(
                "Validado",
                value=usuario.get("validado", False),
                key=f"editar_usuario_zona_validado_{email_original}"
            )

        redefinir = st.checkbox(
            "Redefinir senha",
            value=False,
            key=f"editar_usuario_zona_redefinir_{email_original}"
        )

        nova_senha = ""
        confirmar_senha = ""

        if redefinir:
            col_s1, col_s2 = st.columns(2)
            with col_s1:
                nova_senha = st.text_input(
                    "Nova senha",
                    type="password",
                    key=f"editar_usuario_zona_senha_{email_original}"
                )
            with col_s2:
                confirmar_senha = st.text_input(
                    "Confirmar nova senha",
                    type="password",
                    key=f"editar_usuario_zona_confirma_{email_original}"
                )

        salvar = st.form_submit_button("Salvar usuário da Zona", type="primary")

    if salvar:
        if not nova_zona or nova_zona == "Não informado" or not numero_zona_eleitoral(nova_zona):
            st.warning("Informe a zona eleitoral vinculada.")
            return

        if not novo_nome.strip():
            st.warning("Informe o nome de exibição.")
            return

        if not email_institucional(novo_email):
            st.warning(f"O e-mail deve terminar com {DOMINIO_INSTITUCIONAL}.")
            return

        if novo_email != email_original and any(normalizar_email(u.get("email")) == novo_email for u in lista):
            st.warning("Já existe outro usuário com este e-mail.")
            return

        if redefinir:
            if not nova_senha or len(nova_senha) < 6:
                st.warning("A nova senha deve ter pelo menos 6 caracteres.")
                return
            if nova_senha != confirmar_senha:
                st.warning("As senhas não conferem.")
                return

        usuario["nome"] = novo_nome.strip()
        usuario["email"] = novo_email
        usuario["perfil"] = "Zona Eleitoral"
        usuario["secao_operador"] = ""
        usuario["zona_eleitoral"] = nova_zona
        usuario["ativo"] = ativo
        usuario["validado"] = validado
        usuario["atualizado_em"] = agora_iso()

        if redefinir:
            usuario["senha_hash"] = senha_hash(nova_senha)
            usuario["token_recuperacao"] = ""

        salvar_usuarios(lista)
        st.success("Usuário da Zona atualizado.")
        st.rerun()

    st.divider()
    st.markdown("### Excluir usuário de Zona")

    confirmar = st.checkbox(
        f"Confirmo a exclusão do usuário {usuario.get('email')}",
        key=f"excluir_usuario_zona_confirma_{email_original}"
    )

    if st.button("Excluir usuário da Zona", type="secondary", key=f"excluir_usuario_zona_{email_original}"):
        if not confirmar:
            st.warning("Marque a confirmação antes de excluir.")
        else:
            nova_lista = [
                u for u in lista
                if normalizar_email(u.get("email")) != email_original
            ]
            salvar_usuarios(nova_lista)
            st.success("Usuário da Zona excluído.")
            st.rerun()




